import { Question } from "../types";

// Fragenpool aus dem Original-Excel-Quiz "Psychologie" (213 Fragen, alle Single-Choice).
export const psychologieFragen: Question[] = [
  { id: "ps-1", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Zu den Aufgaben der Psychologie zählen", options: ["Erhalten der seelischen Gesundheit von Menschen.", "Beschreiben, erklären, vorhersagen und beeinflussen von Verhalten.", "Unterstützung von Lehrern und Erziehern in Fragen der Erziehung von Kindern und Jugendlichen.", "Ausbildung von Therapeuten."], correctIndices: [1] },
  { id: "ps-2", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Welche der folgenden Skizzen wäre ein Beispiel für eine korrelative Studie?", options: ["Je höher der Bildungsabschluss der Eltern, desto höher ist der erwartete Bildungsabschluss der Kinder.", "Schüler, die in Lernstrategien unterrichtet werden, schneiden in Behaltenstests besser ab.", "Korrelative Studien werden in der Pädagogischen Psychologie nicht durchgeführt.", "Finnische Schüler und Schülerinnen schneiden in Lesetests besser ab als deutsche."], correctIndices: [0] },
  { id: "ps-3", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Empirisch ist eine Fragestellung, wenn", options: ["sich mindestens zwei Personen darauf geeignet haben, dass sie ein bestimmtes Phänomen beobachtet haben.", "sich ein bestimmtes Phänomen in den Erfahrungen bei Menschen aus verschiedenen Kulturen findet.", "sich die in der Fragestellung enthaltenen Konstrukte übereinstimmend definieren lassen.", "sich die in der Fragestellung enthaltenen Konstrukte operational definieren lassen, so dass sie beobachtbar oder messbar werden."], correctIndices: [3] },
  { id: "ps-4", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Welche Fragestellung eignet sich für ein Experiment?", options: ["Wie gut sind zweisprachig aufgewachsene Kinder in ihrer ersten Fremdsprache in der Schule?", "Warum verhalten sich manche Menschen nach einer Frustration aggressiv und andere nicht?", "Ab wann sollte ein Kind in der Entwicklung soweit sein, die Gefühle von anderen Menschen zu verstehen?", "Lernen Schüler und Schülerinnen ein physikalisches Gesetz schneller, wenn sie am Computer experimentieren oder wenn sie ein tatsächliches Experiment machen?"], correctIndices: [3] },
  { id: "ps-5", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Welche Formulierung trifft am ehesten auf den Gegenstand der Psychologie zu?", options: ["Gegenstand der Psychologie ist die Entwicklung des Menschen.", "Psychologie ist die Wissenschaft von der Seele des Menschen.", "Gegenstand der Psychologie ist das Erleben und Verhalten des Menschen.", "Gegenstand der Psychologie ist das bewußte und unbewußte Denken des Menschen."], correctIndices: [2] },
  { id: "ps-6", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Es ist typisch für korrelative Studien, dass", options: ["ein Untersuchungsleiter verschiedene Gruppen unter verschiedenen Bedingungen prüft.", "repräsentative Gruppen beschrieben werden.", "der Zusammenhang zwischen zwei Merkmalen von Personen untersucht wird.", "die Beziehung zwischen Personen untersucht wird."], correctIndices: [2] },
  { id: "ps-7", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Welche Aussage über das Verhältnis von Empirie und Theorie trifft im Selbstverständnis der Psychologie zu?", options: ["Aus Theorien werden empirische Fragen abgeleitet, die dann untersucht werden können.", "Aus Theorien werden empirische Fragen abgeleitet, die untersucht werden können, wobei die Forschungsergebnisse dazu dienen können, die Theorien zu verändern.", "Theorie und empirische Forschung existieren nebeneinander und haben nichts miteinander zu tun.", "Theorien werden aufgrund von empirischen Daten entwickelt."], correctIndices: [1] },
  { id: "ps-8", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Eine typische Beobachtungsmethode in der entwicklungspsychologischen Kleinkindforschung ist", options: ["die Tagebuchmethode.", "die Gelegenheitsbeobachtung.", "systematische Fremdbeobachtung.", "die systematische Retrospektion."], correctIndices: [2] },
  { id: "ps-9", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Eine Lehrerin soll die Fähigkeit ihrer Schüler und Schülerinnen in der 5. Klasse zum selbstständigen Arbeiten beurteilen. Welche Beobachtungsstrategie ist aus wissenschaftlicher Sicht sinnvoll?", options: ["Sie fragt die Schüler und Schülerinnen nach ihren Selbsteinschätzungen.", "Sie beobachtet gezielt die Schüler und Schülerinnen, die sie für stark hält, um diese zu fördern.", "Sie beobachtet alle Schüler und Schülerinnen mit denselben Kriterien anhand eines Beobachtungssystems ungefähr gleich lang.", "Sie beobachtet gezielt die Schüler und Schülerinnen, die sie für schwach hält, um diese zu fördern."], correctIndices: [2] },
  { id: "ps-10", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Ein wichtiges Entwicklungsprinzip ist", options: ["der Erziehungsstil.", "die Förderung.", "die Universalität.", "das Entwicklungsplateau."], correctIndices: [2] },
  { id: "ps-11", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Was könnte ein Nachteil von Längsschnittsuntersuchungen sein?", options: ["Die Versuchspersonen verlieren die Motivation, kennen die Tests und haben einen Übungseffekt.", "Die Alterstrends können nicht repliziert werden.", "Die Versuchspersonen werden in ihrer Entwicklung beeinflusst und die Daten werden verzerrt.", "Es fallen Versuchspersonen aus, die z.B. aus dem Untersuchungsgebiet wegziehen."], correctIndices: [0] },
  { id: "ps-12", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Was könnte den Erkenntnisgewinn aus Längsschnittuntersuchungen gefährden?", options: ["Eine Längsschnittstudie kostet viel Zeit und Geld.", "Die Versuchspersonen werden zu stark beansprucht.", "Eine Längsschnittstudie kann den Zeitpunkt verpassen, an dem ein Entwicklungsschritt stattfindet.", "Es kann zu einem selektiven Ausfall von Versuchspersonen kommen und eine Gruppe, die besonders interessant wäre, fällt damit aus."], correctIndices: [3] },
  { id: "ps-13", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Eine Lehrerin stellt fest, dass die Schüler und Schülerinnen ihrer 6. Klasse Probleme damit haben, aus einem Text das Wesentliche herauszulesen. Entwicklungspsychologisch kann man das so deuten:", options: ["Der Text ist zu schwer und die Lehrerin sollte den Schülern und Schülerinnen das Wichtigste einfach diktieren.", "Die Schüler und Schülerinnen müssen noch lernen zu verstehen, was das Wichtigste ist und wie man es findet.", "Die Schüler und Schülerinnen haben wahrscheinlich keine Motivation, sich mit schwierigen Texten zu befassen.", "Die Schüler und Schülerinnen sind heute im Lesen nicht mehr so geschickt wie früher."], correctIndices: [1] },
  { id: "ps-14", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Typisch für eine Querschnittsstudie ist, dass", options: ["zu einem Zeitpunkt Probanden verschiedenen Alters untersucht werden.", "individuelle Entwicklungsverläufe sichtbar gemacht werden können.", "alle Probanden nur einen Fragebogen ausfüllen.", "zu einem Zeitpunkt ein Querschnitt der Bevölkerung befragt wird"], correctIndices: [0] },
  { id: "ps-15", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Typisch für eine Querschnittsstudie ist, ...", options: ["... dass Versuchspersonen mehrfach befragt werden, um über die Altersphasen hinweg Information zu erhalten.", "... dass zu einem Zeitpunkt Personen unterschiedlichen Alters untersucht werden.", "... dass Versuchspersonen ausfallen, weil sie die Testwiederholungen nicht mehr mitmachen wollen.", "... dass individuelle Entwicklungsverläufe quer über die Lebensphasen hinweg sichtbar werden."], correctIndices: [1] },
  { id: "ps-16", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Welche Tätigkeiten gehören zu den Aufgaben der Entwicklungspsychologie?", options: ["Untersuchung von Kindern und Jugendlichen auf normgerechte Entwicklung.", "beobachten und beschreiben von Veränderungen im Erleben und Verhalten über die Zeit.", "Beratung von Eltern und Erziehern.", "Entwicklung von Erziehungshinweisen."], correctIndices: [1] },
  { id: "ps-17", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Die IGLU Studie hat die Leseleistung von Viertklässlern getestet und Pisa hat im selben Jahr die Leseleistung von 15jährigen getestet. Die deutschen Viertklässler schnitten im internationalen Vergleich besser ab als die 15jährigen. Welche Schlussfolgerung ist richtig?", options: ["Es gibt einen Trend dahingehend, dass die Leseleistung der 15 jährigen Schüler und Schülerinnen (PISA) im internationalen Vergleich weniger differenziert ausgebildet ist als in der Grundschule (IGLU).", "Die relative Leseleistung von Schülern in Deutschland nimmt von der 4. zu 9. Klasse hin ab.", "Die allgemein bildenden Schulen verderben die Motivation der Schüler und Schülerinnen und damit ihre Leistung.", "Die IGLU Studie war leichter als die PISA Studie. Dass die deutschen Schüler lesen können, sieht man an den guten Ergebnissen bei IGLU. Lesen verlernt man nicht."], correctIndices: [0] },
  { id: "ps-18", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Das entscheidende Moment bei der Akkomodation im Sinne Piagets ist, dass", options: ["das Individuum abstrakte Regeln aus einem Versuchs- und Irrtumsverhalten erkennt.", "das Individuum vorhandene Schemata so verändert, dass es sich den Umweltgegebenheiten anpasst.", "das Individuum gedanklich Hypothesen aufstellen und prüfen kann.", "das Individuum bekannte Schemata und Verhaltensweisen auf neue Objekte überträgt."], correctIndices: [1] },
  { id: "ps-19", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Aus der Zwillingsforschung weiß man,", options: ["dass Umwelt und genetische Disposition unwichtig sind. Es kommt immer auf den Einzelfall an.", "dass die genetische Disposition weniger wichtig ist als die Umwelt.", "dass genetische Dispositionen eine wichtige Rolle in der Entwicklung von Erleben und Verhalten spielen.", "dass die genetische Disposition bis in die Berufswahl hinein wirkt."], correctIndices: [2] },
  { id: "ps-20", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Beschreibende Modelle in der Entwicklungspsychologie", options: ["suchen nach Entwicklungs-\"motoren\".", "suchen nach Ressourcen und Risikofaktoren, z.B. Temperament.", "untersuchen verschiedene Entwicklungsbereiche.", "sind immer Lerntheorien."], correctIndices: [2] },
  { id: "ps-21", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Wenn sich ein Kind im Alter von etwa 3 Jahren die Augen zuhält und meint, dass die Anderen es dann nicht mehr sehen können, ist das im Sinne Piagets ein Beispiel für", options: ["Objektpermanenz.", "Assimilation.", "Kindlichen Egozentrismus.", "Akkomodation."], correctIndices: [2] },
  { id: "ps-22", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Welches sind die von Piaget postulierten invarianten Funktionen der Entwicklung?", options: ["Organisation, Operation, Konstruktion.", "Schema, Interaktion und Äquilibration.", "Organisation, Adaptation, Lernen und Interaktion.", "Organisation, Adaptation, Assimilation und Akkommodation."], correctIndices: [3] },
  { id: "ps-23", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Nachahmung einer symbolischen Handlung, z.B. \"so tun\" als würde man essen, gelingt Kindern nach Piaget erstmals in der", options: ["Phase des präoperationalen Denkens.", "Phase der konkreten Operation.", "sensumotorischen Phase.", "Phase der formalen Operationen."], correctIndices: [2] },
  { id: "ps-24", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Wenn ein Kind zwei Reihen von Münzen vergleicht und beide Reihen gleich viele Münzen enthalten, aber eine weiter auseinandergezogen ausgelegt wird und dann auf die Frage, ob beide Reihen gleich viele Münzen enthält oder eine mehr Münzen enthält, auf die langgezogene Reihe deutet, dann ist das Kind nach Piaget in der", options: ["Phase des konkret-operationalen Denkens.", "Phase des formalen Denkens.", "Phase des präoperationalen Denkens.", "sensumotorischen Phase."], correctIndices: [2] },
  { id: "ps-25", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Es ist typisch für Kategorisierungsleistungen von Kindern in der Phase des formalen Denkens, dass sie", options: ["Gegenstände differenziert und nach verschiedenen Gesichtspunkten ordnen können.", "Gegenstände nach offensichtlichen Merkmalen ordnen können.", "Gegenstände, die sie nicht kennen, gar nicht ordnen können.", "einfache Klassifikationen vornehmen können, diese aber nicht umkehren können."], correctIndices: [0] },
  { id: "ps-26", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Ein Kind in der Phase des präoperativen Denkens nach Piaget versagt wahrscheinlich bei der folgenden Aufgabe:", options: ["Klassifikation von verschiedenen Elementen, z.B. Vögel sind Tiere, die fliegen können, in Ober- und Unterkategorien.", "Nachahmung einer symbolischen Handlung.", "Suche nach einem verdeckten Gegenstand.", "Feststellung von Ursache und Wirkung bei einem motorischen Experiment (z.B. einen Gegenstand herbeiholen, indem es an der Tischdecke zieht, auf dem dieser steht)."], correctIndices: [0] },
  { id: "ps-27", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Welchen Faktor betonen die Reifungstheorien als \"Entwicklungsmotor\"?", options: ["die Lernumwelt.", "die genetische Veranlagung.", "die Selbstgestaltung.", "das Erziehungsverhalten der Eltern."], correctIndices: [1] },
  { id: "ps-28", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Ein Kind in der Phase der formalen Operationen unterscheidet sich nach Piaget von einem Kind in der vorausgehenden Phase dadurch, dass", options: ["dass es Transformationen rückgängig machen kann.", "den Erhalt von Mengen nach einer Transformation erkennen kann.", "dass es Klassifikationen erstellen kann.", "es Vorhersagen über den Ausgang eines Experiments machen kann."], correctIndices: [3] },
  { id: "ps-29", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Das systematische Testen von Hypothesen gelingt den Kindern (nach Piaget)", options: ["in der sensumotorischen Phase.", "in der Phase des präoperationalen Denkens.", "in der Phase des formalen Denkens.", "in der konkret-operationalen Phase."], correctIndices: [2] },
  { id: "ps-30", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Ein zentrales Argument, das die Vertreter der Informationsverarbeitungstheorie gegen Piaget ins Feld führen, lautet:", options: ["Entwicklungsprozesse sind kulturell deutlich stärker unterschiedlich als von Piaget angenommen.", "Kognitive Fähigkeiten von Kindern hängen von deren faktischer Wissensbasis und deren Vorerfahrungen ab.", "Entwicklung geht schneller voran, als Piaget das gesehen hat.", "Entwicklung geschieht nicht so sehr durch Adaptation als durch metakognitive Prozesse"], correctIndices: [1] },
  { id: "ps-31", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Vertreter der Informationsverarbeitungstheorie kritisieren an Piagets Entwicklungstheorie, dass", options: ["das Vorwissen der Kinder nicht berücksichtigt wird.", "die invarianten Funktionen nicht zutreffen.", "die Kinder in der Phase der formalen Operationen überschätzt werden.", "die Lebensspanne nicht ausgeschöpft wird."], correctIndices: [0] },
  { id: "ps-32", subject: "psychologie", topic: "Lernstrategien", question: "Die Entwicklung von Lernstrategien über die Zeit kann man am besten so charakterisieren:", options: ["Die Aufmerksamkeitsspanne wird immer länger.", "Lernstrategien werden zunehmend differenziert und flexibel an den Stoff angepasst.", "Kinder im Übergang von der Grundschule in die Sekundarstufe I nutzen immer mehr Wiederholungsstrategien.", "Kinder im Übergang von der Grundschule in die Sekundarstufe I nutzen immer weniger Elaborationsstrategien, was man daran erkennt, dass sie weniger lang und breit erzählen."], correctIndices: [1] },
  { id: "ps-33", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "In welchem Aspekt sind sich Piaget und die Vertreter der Informationsverarbeitungstheorie in ihren Annahmen über Entwicklung einig?", options: ["Entwicklung ist ein natürlicher Prozess der Selbstentfaltung, bei dem alles mit der Zeit reift.", "Das Kind ist ein \"unbeschriebenes Blatt\" und Entwicklung wird maßgeblich durch Lernangebote von außen gesteuert.", "Entwicklung ist ein aktiver und konstruktiver Prozess, der vom Individuum gesteuert wird.", "Entwicklung ist ein Prozess, der genetisch angelegt ist und von außen eher wenig beeinflusst werden kann."], correctIndices: [2] },
  { id: "ps-34", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Das Ziel eines Experiments ist", options: ["die Überprüfung von Hypothesen.", "die Beschreibung von Verhalten und Erleben.", "die Erkundung von Störvariablen.", "die Generierung von Hypothesen."], correctIndices: [0] },
  { id: "ps-35", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Ein Lehrer macht mit seiner Klasse ein \"Experiment\". Er lässt die Schüler und Schülerinnen einen bestimmten Teil des Stoffes (hier: das Drehmoment in der Physik) selbständig am Computer lernen. Im forschungsmethodischen Sinne ist das so zu bewerten:", options: ["Das ist kein Experiment, weil die Kontrollgruppe und die zufällige Zuordnung der Personen zu den Versuchsbedingungen fehlt.", "Das ist kein Experiment, weil der Lehrer nicht sicher sein kann, dass die Schüler und Schülerinnen den Stoff nicht schon kennen.", "Das ist ein Experiment, weil der Lehrer etwas ausprobiert, dessen Ergebnis er nicht kennt und was für die Klasse neu ist.", "Das ist ein Experiment, weil der Lehrer das Programm zufällig gefunden hat."], correctIndices: [0] },
  { id: "ps-36", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Für ein Experiment eignet sich die folgende Fragestellung:", options: ["Finnische Schüler und Schülerinnen können am Ende der 8. Klasse besser rechnen als ihre deutschen Altersgenossen.", "Wenn Schüler und Schülerinnen eine Vokabelliste mit Musik im Hintergrund memorieren, dann behalten sie mehr Vokabeln, als wenn sie eine gleichlange Liste bei Stille memorieren.", "Kinder von Müttern, die Vollzeit arbeiten sind in der Entwicklung im Vergleich zu Kindern von Müttern, die Zuhause bleiben, benachteiligt.", "Männer können besser einparken als Frauen."], correctIndices: [1] },
  { id: "ps-37", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Bestandteile des Experiments sind", options: ["Unabhängige Variable, Störvariable, Abhängige Variable.", "Manipulation, Arbeitshypothese, Gedächtnisinhalte, Verhaltensbeobachtung.", "Unabhängige Variable, Abhängige Variable, Arbeitshypothese, Randomisierung.", "Arbeitshypothese, Nullhypothese, Störvariable und Kontrollgruppe."], correctIndices: [2] },
  { id: "ps-38", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Eine Wissenschaftlerin möchte untersuchen, ob bestimmte Inhalte (hier: Wortlisten) besser erinnert werden, wenn die Situation, in der abgefragt wird, der Situation, in der gelernt wurde, ähnlich ist. Zwei Gruppen: A) Lernen und Abfragen mit Schokoladenduft, B) Lernen mit Duft, Abfragen duftneutral. Was ist die unabhängige Variable?", options: ["die unabhängige Variable sind die Versuchspersonen.", "dieses Experiment hat keine unabhängige Variable, weil alles mit allem zusammenhängt.", "die unabhängige Variable ist die Manipulation des Duftes im Hintergrund.", "die unabhängige Variable ist die Anzahl der Begriffe, die sich die Probanden aus den Wortlisten behalten."], correctIndices: [2] },
  { id: "ps-39", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Ein Quasi-Experiment unterscheidet sich von einem Experiment dadurch, dass", options: ["die abhängige Variable nicht vom Versuchsleiter bestimmt wird.", "es nur hypothetisch als Gedankenexperiment durchgeführt wird.", "keine Hypothese vorab aufgestellt wird.", "die unabhängige Variable nicht vom Versuchsleiter variiert wird."], correctIndices: [3] },
  { id: "ps-40", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Wenn man davon spricht, dass Randomisierung ein wesentliches Element des Experiments darstellt, so meint man damit folgendes:", options: ["Die Arbeitshypothese wird zufällig ausgewählt.", "Die Versuchspersonen werden den Versuchsbedingungen zufällig zugeordnet.", "Die Versuchsbedingungen werden zufällig hergestellt.", "Man untersucht die Leute, die zufällig vorbei kommen."], correctIndices: [1] },
  { id: "ps-41", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Wenn ein Wissenschaftler feststellen möchte, ob Jungen oder Mädchen den Umgang mit einem Computerprogramm schneller lernen, so ist das", options: ["es kann beides sein.", "ein Experiment.", "kann man so nicht entscheiden.", "ein Quasi-Experiment."], correctIndices: [3] },
  { id: "ps-42", subject: "psychologie", topic: "Gedächtnis", question: "Wenn eine Lehrerin den Schülern und Schülerinnen eine Methode erklärt, wie sie am besten englische Vokabeln memorieren können, dann zielt das auf", options: ["perzeptuelles Wissen.", "prozedurales Wissen.", "semantisches Wissen.", "deklaratives Wissen."], correctIndices: [1] },
  { id: "ps-43", subject: "psychologie", topic: "Gedächtnis", question: "Welche Aussage über das Langzeitgedächtnis ist richtig?", options: ["Das Langzeitgedächtnis enthält nur implizite Gedächtnisinhalte.", "Das Langzeitgedächtnis enthält bis zu sieben Elemente.", "Das Langzeitgedächtnis enthält alle Arten von Gedächtnisinhalten.", "Die typische Repräsentationsform im Langzeitgedächtnis ist dem externen Reiz sehr ähnlich."], correctIndices: [2] },
  { id: "ps-44", subject: "psychologie", topic: "Gedächtnis", question: "Wenn ein Schüler die eben gesprochenen Worte eines Lehrers wiedergeben kann, so ist das", options: ["eine Leistung des Langzeitgedächtnisses (weil der Lehrer immer dasselbe sagt).", "gar keine Leistung.", "eine Leistung des Ultrakurzzeitgedächtnisses.", "eine Leistung des Kurzzeitgedächtnisse."], correctIndices: [2] },
  { id: "ps-45", subject: "psychologie", topic: "Gedächtnis", question: "Ein Beispiel für Elaborationen als Gedächtnisstrategie wäre", options: ["Einplanung von Pausen.", "Kategorisierung von Material.", "Unterstreichen von wichtigen Elementen.", "Kommentare zum Lerninhalt hinzufügen."], correctIndices: [3] },
  { id: "ps-46", subject: "psychologie", topic: "Gedächtnis", question: "Welche Aussagen über Gedächtnisstrategien ist richtig?", options: ["Gedächtnisstrategien fördern nur das Aufnehmen von Information.", "Gedächtnisstrategien fördern nur das Abrufen von Information.", "Gedächtnisstrategien fördern das Aufnehmen, Abspeichern und Abrufen von Information.", "Gedächtnisstrategien fördern das Abspeichern von Information."], correctIndices: [2] },
  { id: "ps-47", subject: "psychologie", topic: "Gedächtnis", question: "Bei Wiederholungsstrategien kann man die Wirksamkeit fördern, indem", options: ["man die zu wiederholenden Begriffe laut vorsagt.", "man nach dem Wiederholen etwas Aufregendes und Spannendes unternimmt.", "man auf keinen Fall Pausen macht.", "man die Wiederholungen über die Zeit verteilt."], correctIndices: [3] },
  { id: "ps-48", subject: "psychologie", topic: "Unterricht & Klassenführung", question: "Als Lehrer oder Lehrerin können Sie die Informationsverarbeitung fördern, indem Sie", options: ["Fragen möglichst ausschmücken.", "Fragen am besten selbst beantworten.", "nach einer Frage möglichst unmittelbar einen Schüler aufrufen.", "nach einer Frage eine Wartezeit einhalten"], correctIndices: [3] },
  { id: "ps-49", subject: "psychologie", topic: "Lernstrategien", question: "Was beachten Sie, wenn Sie als Lehrer oder Lehrerin Lernstrategien vermitteln?", options: ["Lernstrategien erklären Sie am besten am Schuljahresanfang, dann brauchen Sie darauf nicht wieder einzugehen.", "Sie achten darauf, dass die Schüler und Schülerinnen vor allem Wiederholungsstrategien üben, denn die Wiederholung ist die Mutter allen Lernens.", "Lernstrategien können Sie gar nicht beeinflussen, da müssen die Schüler und Schülerinnen selbst drauf kommen.", "Lernstrategien vermitteln Sie in Zusammenhang mit dem Stoff, den Sie darbieten."], correctIndices: [3] },
  { id: "ps-50", subject: "psychologie", topic: "Gedächtnis", question: "Das Kurzzeitgedächtnis und das Langzeitgedächtnis unterscheiden sich hinsichtlich", options: ["des Aspekts explizit und implizit.", "des Inhalts.", "der Kapazität.", "der Komplexität."], correctIndices: [2] },
  { id: "ps-51", subject: "psychologie", topic: "Gedächtnis", question: "Wenn ein Lehrer seine Schüler und Schülerinnen auffordert, englische Vokabeln zu memorieren, dann zielt das auf die Aneignung von", options: ["deklarativem Wissen.", "episodischem Wissen.", "perzeptuellem Wissen.", "prozeduralen Wissen."], correctIndices: [0] },
  { id: "ps-52", subject: "psychologie", topic: "Gedächtnis", question: "Langzeitspeicher und sensorisches Register unterscheiden sich", options: ["in der Repräsentationsform.", "in der Bedeutung.", "in der Kapazität.", "im Inhalt."], correctIndices: [0] },
  { id: "ps-53", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Aus der Sicht der Theorie des operanten Konditionierens ist Bestrafung der Art, dass einem Lernenden auf unerwünschtes Verhalten etwas Negatives angetan wird,", options: ["wenig effektiv, weil derjenige, der bestraft, sich unglaubwürdig macht.", "wenig effektiv, weil auf diese Weise nicht klar wird, was das erwünschte Verhalten wäre.", "sinnvoll, weil Verhalten so gelöscht wird.", "wenig effektiv, weil man sehr häufig strafen muss, bevor es wirkt."], correctIndices: [1] },
  { id: "ps-54", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Wenn Sie im Auto sitzen und sich nicht anschnallen, erfolgt ein unangenehmer Ton. Sobald Sie sich anschnallen, verschwindet der Ton. In der Terminologie des operanten Konditionierens ist das", options: ["eine Bestrafung.", "programmiertes Lernen.", "eine positive Verstärkung.", "eine negative Verstärkung."], correctIndices: [3] },
  { id: "ps-55", subject: "psychologie", topic: "Konditionieren & Lernen", question: "In seinen Experimenten zur Untersuchung der Nachahmung von aggressiven Verhaltensweisen konnte Bandura in den 60er Jahren folgendes zeigen:", options: ["Kinder ahmen häufiger aggressives Verhalten nach, wenn das Modell für dasselbe Verhalten verstärkt worden ist.", "Ob Kinder ein aggressives Modell nachahmen, hängt in erster Linie von dem Temperament des Kindes ab.", "Mädchen ahmen weniger aggressives Verhalten nach als Jungen.", "Kinder ahmen aggressives Verhalten immer nach, wenn sie ein aggressives Modell beobachten konnten."], correctIndices: [0] },
  { id: "ps-56", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Es ist ein Kennzeichen des Behaviorismus, dass", options: ["ausschließlich Reflexe untersucht werden.", "ausschließlich kognitive Prozesse untersucht werden.", "ausschließlich beobachtbares Verhalten untersucht wird.", "ausschließlich Tiere untersucht werden."], correctIndices: [2] },
  { id: "ps-57", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Im Fall des Kleinen Albert ist der Schrecken, den der Junge auf das Knallgeräusch zeigt", options: ["der unkonditionierte Reflex.", "der diskriminative Stimulus.", "der konditionierte Stimulus.", "der unkonditionierte Stimulus."], correctIndices: [0] },
  { id: "ps-58", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Eine Lehrerin möchte erreichen, dass ein schüchterner Schüler sich traut, im Unterricht etwas laut in der Klasse zu sagen. Es ist aus der Sicht des operanten Konditionierens sinnvoll,", options: ["eine Situation herzustellen, in dem es dem Schüler leichter fallen könnte, etwas zu sagen und das Verhalten sofort loben.", "abzuwarten, bis der Schüler einmal etwas sagt und ihn dann sofort loben.", "abzuwarten, bis der Schüler einmal etwas sagt und ihn dann am Ende des Schultages zu loben.", "eine Situation herzustellen, in dem es dem Schüler leichter fallen könnte, etwas zu sagen und das Verhalten ignorieren."], correctIndices: [0] },
  { id: "ps-59", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Wenn ein Lehrer einem Schüler ein Fleißbildchen für eine gelungene Arbeit gibt, so ist das in der Terminologie des operanten Konditionierens ...", options: ["eine negative Verstärkung.", "eine positive Verstärkung.", "eine pädagogische Verhaltensmodifikation.", "eine Bestrafung."], correctIndices: [1] },
  { id: "ps-60", subject: "psychologie", topic: "Modelllernen", question: "Welches Merkmal erhöht die Wahrscheinlichkeit, dass ein Modell nachgeahmt wird?", options: ["Reichtum.", "Alter.", "Gutes Aussehen.", "gute Beziehung zum Lerner."], correctIndices: [3] },
  { id: "ps-61", subject: "psychologie", topic: "Modelllernen", question: "Ein Lehrer möchte gern, dass seine Schüler und Schülerinnen eine mathematische Aufgabe auf eine bestimmte Weise lösen. Er erklärt ihnen, dass das besonders für Anfänger wichtig sei, während er selbst ein abgekürztes Verfahren nutzt. Aus der Sicht der Theorie von Modell-Lernen ist dazu das folgende zu sagen:", options: ["Dadurch, dass der Lehrer seinen Wissensvorsprung zeigt, ist er ein gutes Modell dafür, wie weit man es bringen kann und die Schüler eifern ihm nach.", "Da Schüler auch lernen müssen zu abstrahieren, können sie sich den Lehrer schon mal als Modell nehmen, während sie noch in der Übungsphase sind.", "Dieses Vorgehen eignet sich nicht, weil gerade Anfänger das Modell des Lehrers wiederholt brauchen, um das relevante Verhalten wahrnehmen und speichern zu können.", "Dieses Vorgehen ist besonders gut geeignet, hochbegabte und leistungsorientierte Schüler herauszufordern."], correctIndices: [2] },
  { id: "ps-62", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Wenn ein Wissenschaftler ein Versuchstier dazu bringen will, ein neues Verhalten zu lernen, dann ist der folgende Verstärkungsplan sinnvoll:", options: ["Intervallverstärkung.", "intermittierende Verstärkung.", "Immerverstärkung.", "Bestrafung."], correctIndices: [2] },
  { id: "ps-63", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Die Theorie von Thurstone geht von folgenden Primärfaktoren aus:", options: ["kristalline und fluide Intelligenz.", "Generalfaktor plus mehrere spezifische, aber weniger bedeutsame Faktoren.", "Analytische, kreative und praktische Intelligenz.", "Faktoren wie Wortflüssigkeit, räumliches Vorstellungsvermögen, Gedächtnis, Analoges Schlussfolgern."], correctIndices: [3] },
  { id: "ps-64", subject: "psychologie", topic: "Persönlichkeitspsychologie", question: "Welche Aussage über Persönlichkeitsmerkmale ist aus der Sicht der Psychologie richtig?", options: ["Persönlichkeitsmerkmale sind konstruierte Merkmale, die nur in bestimmten Situationen (z.B. in Tests) beobachtbar sind.", "Persönlichkeitsmerkmale sind relativ stabile und situationsübergreifend beobachtbare Merkmale.", "Persönlichkeitsmerkmale sind niemals beobachtbar und niemals quantifizierbar.", "Persönlichkeitsmerkmale sind gar nicht beobachtbar, sondern in der Person verborgen."], correctIndices: [1] },
  { id: "ps-65", subject: "psychologie", topic: "Persönlichkeitspsychologie", question: "Ein Persönlichkeitsmerkmal nennt man hypothetisches Konstrukt, weil...", options: ["weil es mit Hypothesen getestet wird.", "weil es aus Indikatoren erschlossen wird.", "es nur vielleicht existiert.", "es wahrscheinlich gar nicht existiert."], correctIndices: [1] },
  { id: "ps-66", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Wenn man sagt, ein Test sei reliabel, dann ist damit gemeint, dass", options: ["er leicht ist und von allen gut bewältigt werden kann.", "er nachweislich misst, was er messen soll.", "das Testergebnis tabelliert und an einer Eichstichprobe normiert ist.", "der Test im Wiederholungsfall zum selben oder sehr ähnlichen Ergebnis kommt."], correctIndices: [3] },
  { id: "ps-67", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Ein Intelligenztest ist valide, wenn", options: ["das Ergebnis, das jemand im Intelligenztest hat und das Ergebnis in einem Ängstlichkeitstest übereinstimmen.", "das Ergebnis, das jemand im Intelligenztest hat und das Ergebnis in einem Problemlösetest in etwa übereinstimmen.", "das Ergebnis, das jemand im Intelligenztest hat und das Ergebnis in einem Aufmerksamkeitstest in etwa übereinstimmen.", "das Ergebnis, das jemand im Intelligenztest hat und das Ergebnis in einem Kreativitätstest in etwa übereinstimmen."], correctIndices: [1] },
  { id: "ps-68", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Ein Indikator für Intelligenz könnte sein:", options: ["Fähigkeit zur Aufmerksamkeitskontrolle.", "Leistung in Problemlöseaufgaben.", "Neigung zu Zittrigkeit in Testsituationen.", "Fähigkeit zur Kommunikation."], correctIndices: [1] },
  { id: "ps-69", subject: "psychologie", topic: "Persönlichkeitspsychologie", question: "Ein Beispiel für ein affektives Persönlichkeitsmerkmal ist", options: ["Aufmerksamkeit.", "Ängstlichkeit.", "Kreativität.", "Analytische Kompetenz."], correctIndices: [1] },
  { id: "ps-70", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Wenn bei einem Test ein Proband für eine Aufgabe 10 Minuten Bearbeitungszeit bekommt und ein anderer Proband 15 Minuten für dieselbe Aufgabe erhält, dann ist das", options: ["eine Verletzung der Validität des Tests, weil dann etwas anderes getestet wird.", "eine Verletzung der Durchführungsobjektivität.", "ein fairer Nachteilsausgleich, weil der eine vielleicht langsamer vorgeht.", "eine qualitative Verbesserung des Tests durch Adaptivität und Flexibilität."], correctIndices: [1] },
  { id: "ps-71", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Welche Aussage über Intelligenztests ist richtig?", options: ["Intelligenztests erzeugen Unterschiede zwischen Personen.", "Wie ein Intelligenztest aussieht, hängt von der Theorie der Intelligenz ab, die der Autor bevorzugt.", "Intelligenztests sind individuell unterschiedliche Prüfungen der Fähigkeit zu denken.", "Mit Hilfe von Intelligenztests kann man Personen ermitteln, die in der Schule erfolgreich sein werden."], correctIndices: [1] },
  { id: "ps-72", subject: "psychologie", topic: "Statistik", question: "Wenn man sagt, ein Merkmal sei normal verteilt, dann ist damit gemeint, dass", options: ["sehr häufig extreme Ausprägungen des Merkmals vorkommen.", "das Merkmal bei den meisten Menschen nicht mehr als eine Standardabweichung vom Mittelwert entfernt ausgeprägt ist.", "das Merkmal bei allen Menschen ungefähr gleich ausgeprägt ist.", "es in einem Merkmal keine Unterschiede zwischen den Menschen gibt."], correctIndices: [1] },
  { id: "ps-73", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Wenn Sie eine Schülerin beobachten, die sehr darum bemüht ist, Fehler zu vermeiden, weil sie Fehler als einen Misserfolg wertet, dann ist sie wahrscheinlich an folgenden Zielen orientiert:", options: ["Nahziele.", "Fernziele.", "Performanzziele.", "Lernziele."], correctIndices: [2] },
  { id: "ps-74", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Aus der Untersuchung von Bandura und Schunk geht hervor, dass Lehrer und Lehrerinnen, um die Leistung und die Motivation zu fördern, ihren Schülerinnen und Schülern", options: ["anspruchsvolle und globale Ziele setzen sollten.", "nahe und konkrete Ziele setzen sollten.", "gar keine Ziele setzen sollten.", "möglichst weit entfernte Ziele setzen sollten."], correctIndices: [1] },
  { id: "ps-75", subject: "psychologie", topic: "Statistik", question: "Wenn eine positive Korrelation zwischen Motivation und Leistung festgehalten wird, dann bedeutet das,", options: ["dass die Leistung nach oben geht, wenn die Motivation abnimmt.", "dass je größer die Motivation, umso größer die Leistung.", "dass Leistung und Motivation von Schülern mit dem Alter zunehmen.", "dass eine hohe Motivation eine Ursache für gute Leistung darstellt."], correctIndices: [1] },
  { id: "ps-76", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Für eine Schülerin mit Performanzzielorientierung (= Leistungszielorientierung) ist es typisch, dass sie", options: ["außer Problemen nichts mehr Positives sieht.", "trotz Problemen sich durchbeißt.", "wegen Problemen schnell heult.", "bei Problemen schnell aufgibt."], correctIndices: [3] },
  { id: "ps-77", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Ein Schüler mit Lernzielorientierung strengt sich wahrscheinlich dann besonders an, wenn er", options: ["eine Chance sieht, seine Klassenkameraden auszustechen.", "eine Möglichkeit sieht, seine Kompetenzen zu erweitern.", "mit einer guten Leistung bei der Lehrerin Eindruck hinterlassen möchte.", "den Misserfolg von anderen herbeiführen kann"], correctIndices: [1] },
  { id: "ps-78", subject: "psychologie", topic: "Statistik", question: "Eine positive Korrelation von r = .65 zwischen der mit Hausaufgaben verbrachten Zeit und der Leistung im Englisch-Test, bedeutet folgendes:", options: ["Je mehr Zeit die Schüler mit Hausaufgaben verbringen, desto besser der Englisch-Test.", "Die Zeit, die Schüler mit Hausaufgaben verbringen, und die Leistung im Englisch-Test haben so gut wie nichts miteinander zu tun.", "Je mehr Zeit die Schüler mit Hausaufgaben verbringen, desto schlechter der Englisch-Test.", "Je weniger Zeit die Schüler mit Hausaufgaben verbringen, desto besser der Englisch-Test."], correctIndices: [0] },
  { id: "ps-79", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Welche Aussage über Motivation ist richtig?", options: ["Die Ausprägung der Motivation hängt eng mit den allgemeinen kognitiven Fähigkeiten zusammen.", "Motivation bei Schülern und Schülerinnen entsteht am besten ohne konkrete Ziele.", "Die Motivation von Schülern und Schülerinnen hängt immer vom Stoff der Stunde ab.", "Die Motivation führt zu erhöhter Anstrengungsbereitschaft der Schüler und Schülerinnen."], correctIndices: [3] },
  { id: "ps-80", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Welches Ergebnis hat die Untersuchung von Bandura und Schunk zur Wirkung von Zielen auf den Lernerfolg erbracht?", options: ["Ziele setzen die Schüler und Schülerinnen unter Druck und die Leistungen fallen stark ab (unter 10% der Ausgangsleistung).", "Ziele lenken die Schüler und Schülerinnen von den Aufgaben ab und sie versuchen nur noch, der/die Erste zu sein, der/die fertig wird.", "Ziele schädigen die Kreativität der Schüler und Schülerinnen und so kommen nur sehr durchschnittliche Arbeitsergebnisse zustande.", "Ziele, die in der ferneren Zukunft liegen, haben keinen Effekt auf die Mengenleistung in der aktuell anstehenden Arbeitsphase."], correctIndices: [3] },
  { id: "ps-81", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Es ist typisch für Reattributionstrainings, dass", options: ["Mädchen stärker auf das Training reagieren als Jungen.", "sich leichter die Erfolgsorientierung stärken als Misserfolgsorientierung abbauen läßt.", "die Effekte sehr schnell sichtbar werden.", "das Training ausschließlich im Fach Mathematik wirksam ist."], correctIndices: [1] },
  { id: "ps-82", subject: "psychologie", topic: "Lernschwierigkeiten", question: "Aus der Sicht der Kognitionspsychologie liegt bei Kindern und Jugendlichen mit Lernschwierigkeiten das folgende Problem vor:", options: ["Die Schüler und Schülerinnen haben zu viele Ablenkungen und schlechte Einflüsse.", "Die Schüler und Schülerinnen haben Probleme mit der Informationsverarbeitung (Auswahl, Gewichtung) und den Lernstrategien.", "Die Schüler und Schülerinnen haben ein schwaches Selbstkonzept und trauen sich nichts zu.", "Die Eltern kümmern sich nicht ausreichend um die schulische Arbeit ihrer Kinder."], correctIndices: [1] },
  { id: "ps-83", subject: "psychologie", topic: "Bewertung & Bezugsnormen", question: "Eine Lehrerin möchte gern einem Schüler, der ein im Vergleich zum Rest seiner Klasse großes Defizit in einem Fach aufzuarbeiten hat, durch angemessene Rückmeldung den Lernfortschritt aufzeigen. Das kann sie am besten erreichen, wenn sie die folgende Norm anwendet:", options: ["soziale Bezugsnorm.", "kriteriale Bezugsnorm.", "institutionelle Norm.", "individuelle Bezugsnorm."], correctIndices: [3] },
  { id: "ps-84", subject: "psychologie", topic: "Lernschwierigkeiten", question: "Zur Beurteilung von Lernschwierigkeiten wird neben der Abweichung von der Norm zusätzlich berücksichtigt,", options: ["ob durch die beobachtete Schwierigkeit die weitere Entwicklung des Kindes beeinträchtigt wird.", "ob es vielleicht noch eine andere, leichtere Schulart gibt, in der man dem Schüler noch eine Chance geben kann.", "was der Lehrer oder die Lehrerin meint.", "ob das Kind oder der Jugendliche einsichtig ist und wirklich auch etwas verändern will."], correctIndices: [0] },
  { id: "ps-85", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Es ist typisch für Schüler und Schülerinnen mit Misserfolgsorientierung, dass", options: ["sie die Ursache für Misserfolge immer bei anderen Personen oder bei äußeren Umständen suchen.", "sie an die Wirkung der eigenen Anstrengung glauben, aber keine Lust dazu haben.", "sie denken, dass sie Erfolge erzielen könnten, wenn sie sich anstrengen würden.", "sie sich Misserfolge damit erklären, dass sie nicht begabt wären oder sowieso mit der Anstrengung nichts bewirken können."], correctIndices: [3] },
  { id: "ps-86", subject: "psychologie", topic: "Bewertung & Bezugsnormen", question: "Ein Schüler verfehlt die soziale Bezugsnorm, wenn", options: ["sein Verhalten nicht den Regeln in der Klasse entspricht.", "er sein Verhalten plötzlich ändert, z.B. wegen einer persönlichen Krise.", "sein Verhalten egoistisch und unsozial ist.", "sein Verhalten nicht dem Alter entspricht."], correctIndices: [0] },
  { id: "ps-87", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Ein Ziel von Re-Attributionstrainings ist es,", options: ["den Kindern und Jugendlichen zu vermitteln, dass sie Erfolge durch ihre eigene Anstrengung erzielen können.", "den Lehrern zu vermitteln, dass auch \"blinde Hühner\" manchmal ein Korn finden.", "den Schülern zu vermitteln, dass an ihren Misserfolgen hauptsächlich andere Personen (Lehrer) und die Umstände schuld sind.", "den Eltern zu vermitteln, dass sie ihren Kindern in der Schule mehr Unterstützung zukommen lassen müssen."], correctIndices: [0] },
  { id: "ps-88", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Eine Schülerin hat in Mathematik einen Erfolg erlebt und eine gute Note in der Klassenarbeit erzielt. Sie sagt: \"Huch!? Ist das meine Arbeit?\" - dann haben Sie als Lehrerin möglicherweise einen Hinweis darauf, dass", options: ["die Schülerin keinen Zusammenhang zwischen ihrem Einsatz und dem Ergebnis sieht und dieses für Zufall hält.", "die Schülerin abgeschrieben hat, weil sie ihre eigene Arbeit kaum noch erkennt.", "die Schülerin kokettiert und in Wirklichkeit genau weiß, wie gut sie ist.", "die Schülerin den Erfolg als ein Ergebnis der eigenen Anstrengung wertet."], correctIndices: [0] },
  { id: "ps-89", subject: "psychologie", topic: "Bewertung & Bezugsnormen", question: "Der Fall, dass alle Schüler und Schülerinnen, die eine Prüfung oder eine Klassenarbeit schreiben, mit dem Ergebnis sehr gut abschneiden, kann nur auftreten, wenn", options: ["die Prüfung vom Lehrer gut vorbereitet wird.", "die Prüfung an einer sozialen Norm ausgerichtet wird.", "die Prüfung sehr leicht ist.", "die Prüfung an einer sachlichen Norm ausgerichtet wird."], correctIndices: [3] },
  { id: "ps-90", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Welche der folgenden Verhaltensweisen gehört zur Symptomatik von Kindern und Jugendlichen mit Aufmerksamkeitsstörungen?", options: ["Misserfolgsorientierung.", "Desinteresse am Schulstoff.", "Sozialer Rückzug.", "Vergessen von Arbeitsanweisungen."], correctIndices: [3] },
  { id: "ps-91", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "In einem Experiment, in dem geprüft wird, ob grell farbiges Papier einen Einfluss auf die Menge und die Güte der Leistungen von Kindern mit ADHS hat, ist die Farbigkeit des Papiers", options: ["die unabhängige Variable.", "die Kontrollvariable.", "die abhängige Variable.", "die Störvariable."], correctIndices: [0] },
  { id: "ps-92", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Welche Aussage über Aufmerksamkeitsstörungen ist richtig?", options: ["3-5% aller Mädchen sind betroffen.", "3-5% aller Kinder sind betroffen.", "3-5% aller Jungen sind betroffen.", "Höchstens 3-5 % aller Kinder haben keine Symptome."], correctIndices: [1] },
  { id: "ps-93", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Welche Aspekte gehören zu den Kernsymptomen der Aufmerksamkeitsstörung?", options: ["Mangel an Selbstbeherrschung, fehlende Motivation, Störungen des Sozialverhaltens.", "Hyperaktivität, Vergesslichkeit und Ablenkbarkeit.", "Störung der Leistungsmotivation, Störung des Sozialverhaltens, gestörte Persönlichkeitsentwicklung.", "Unaufmerksamkeit, Hyperaktivität, Impulsivität."], correctIndices: [3] },
  { id: "ps-94", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Wenn eine Mutter ein Kind mehrfach auffordert, es möge die Büchertasche packen und das Kind dies nicht tut, die Mutter dann laut wird, schimpft und die Tasche selbst packt und sagt: \"Und morgen machst Du das aber selbst, sonst fährst Du am Wochenende nicht mit zur Oma!\", so ist das psychologisch gesehen", options: ["inkonsistentes Erzieherverhalten, das das Kind in seinem unerwünschten Verhalten verstärkt.", "ein Appell der Mutter an die Einsicht des Kindes, selbstständig zu werden.", "ein Modellverhalten zur Demonstration des gewünschten Verhaltens.", "eine Bestrafung zur Erzwingung des erwünschten Verhaltens."], correctIndices: [0] },
  { id: "ps-95", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Welche Aussage trifft zu?", options: ["Kinder und Jugendliche mit Aufmerksamkeitsstörungen können besser lernen, wenn man ihnen Aufgaben leichter macht.", "Kinder und Jugendliche mit Aufmerksamkeitsstörungen können besser lernen, wenn man ihnen möglichst die ganze Aufgabe auf einmal gibt.", "Kinder und Jugendliche mit Aufmerksamkeitsstörungen sind am Gymnasium meist überfordert.", "Kinder und Jugendliche mit Aufmerksamkeitsstörungen können besser lernen, wenn man ihnen hilft, Aufgaben zu portionieren."], correctIndices: [3] },
  { id: "ps-96", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Die Stimulationsdefizithypothese zur Erklärung von ADHS sagt, dass die motorische Unruhe der betroffenen Kinder eine Folge von", options: ["chronischer Unterstimulierung und mangelnder Wachheit ist.", "temporärer Unterstimulierung und mangelnder Wachheit ist.", "temporärer Reizüberflutung und übertriebener Wachheit ist.", "chronischer Reizüberflutung und übertriebener Wachheit ist."], correctIndices: [0] },
  { id: "ps-97", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Von Verhaltensauffälligkeiten spricht man, wenn das Verhalten von Normen abweicht und dazu kommt,", options: ["dass es den Lehrer nervt.", "dass es den Betroffenen und seine Umwelt belastet oder schädigt.", "dass es vor dem 7. Lebensjahr definitiv diagnostiziert worden ist.", "dass es nur Ausdruck einer vorübergehenden Krise ist."], correctIndices: [1] },
  { id: "ps-98", subject: "psychologie", topic: "Vorurteile & Gruppenpuzzle", question: "Zur Definition von \"Vorurteil\" gehört, dass es", options: ["negative Einstellung beschreibt, die sich auf Außenseitergruppen bezieht.", "eine negative Einstellung gegenüber Menschen allein aufgrund ihrer Gruppenzugehörigkeit beschreibt.", "negative und positive Einstellungen beschreibt, die im Vorhinein gebildet werden.", "eine negative Einstellung gegenüber Menschen beschreibt, mit denen man schlechte Erfahrungen gemacht hat."], correctIndices: [1] },
  { id: "ps-99", subject: "psychologie", topic: "Vorurteile & Gruppenpuzzle", question: "Die Kontakthypothese in der Vorurteilsforschung sagt im Prinzip folgendes:", options: ["Das Vorurteil entsteht überhaupt erst im Kontakt mit einer besonderen Gruppe.", "Je mehr Kontakt man zu einer Gruppe hat, gegen die man ein Vorurteil hegt, desto stärker ist das Vorurteil.", "Das Vorurteil ist stärker, wenn der Kontakt innerhalb der eigenen Gruppe besonders eng ist.", "Ein Vorurteil kann abgebaut werden, wenn man mit Mitgliedern der Gruppe, gegen die man das Vorurteil hat, in Kontakt kommt."], correctIndices: [3] },
  { id: "ps-100", subject: "psychologie", topic: "Vorurteile & Gruppenpuzzle", question: "Zu den Bedingungen, die das Gruppenpuzzle stellt, gehört:", options: ["dass jeder ein eigenes, persönliches Ziel verfolgt.", "dass jeder mit jedem zusammenarbeiten möchte.", "dass alle Gruppenmitglieder ein gemeinsames Ziel verfolgen.", "dass alle Gruppenmitglieder vergleichbares Fähigkeitsniveau besitzen."], correctIndices: [2] },
  { id: "ps-101", subject: "psychologie", topic: "Vorurteile & Gruppenpuzzle", question: "Die Untersuchung von Borsch et al. zum Gruppenpuzzle ist methodisch gesehen", options: ["eine Querschnittstudie.", "ein Laborexperiment.", "ein Feldexperiment.", "eine Korrelationsstudie."], correctIndices: [2] },
  { id: "ps-102", subject: "psychologie", topic: "Vorurteile & Gruppenpuzzle", question: "Welche Aussage zum Ergebnis des Experiments von Borsch et al. (2002) zum Gruppenpuzzle ist zutreffend?", options: ["Grundschüler wissen beim Lernen im Gruppenpuzzle auch nach 4 Monaten noch mehr als beim lehrergeleiteten Unterricht.", "Grundschüler sind von der Methode des Gruppenpuzzles schnell gelangweilt.", "Grundschüler sind von der Methode des Gruppenpuzzles schnell überfordert.", "Grundschüler lernen bei der Methode des Gruppenpuzzles genau so viel wie im lehrergeleiteten Unterricht."], correctIndices: [0] },
  { id: "ps-103", subject: "psychologie", topic: "Sozialpsychologie", question: "Zum Gegenstand der Sozialpsychologie gehört die Frage:", options: ["Welche sozialen Gruppen gibt es in unserer Gesellschaft?", "Wie entstehen soziale Unterschiede?", "Wie Verhalten sich Menschen in Gruppen?", "Welchen Einfluss haben gesellschaftliche Gruppen auf die Entwicklung von einzelnen?"], correctIndices: [2] },
  { id: "ps-104", subject: "psychologie", topic: "Sozialpsychologie", question: "Im Asch-Experiment wurde gezeigt, dass", options: ["Menschen in ihrem Urteil meistens autonom sind.", "Menschen psychologische Experimente nicht ernst nehmen.", "Menschen sich von der Minderheitenmeinung beeinflussen lassen und sich dieser anschließen.", "Menschen eine Tendenz haben, sich der Mehrheitsmeinung anzuschließen."], correctIndices: [3] },
  { id: "ps-105", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Es ist typisch für deskriptive Studien, dass", options: ["mindestens zwei Merkmale einer Population miteinander in Beziehung gesetzt werden.", "Ursache und Wirkungs-Zusammenhänge untersucht werden.", "der Stand der Dinge, z.B. des Könnens oder Wissens, einer Gruppe erfasst wird.", "eine Intervention durchgeführt und deren Effekte beschrieben werden."], correctIndices: [2] },
  { id: "ps-106", subject: "psychologie", topic: "Sozialpsychologie", question: "Wenn Psychologen die Frage untersuchen, wie sich das Verhalten von Menschen ändert, wenn andere Menschen präsent sind, dann weist man diese Frage dem folgenden Teilgebiet zu:", options: ["Sozialpsychologie", "Persönlichkeitspsychologie", "Gruppenpsychologie", "Klinische Psychologie"], correctIndices: [0] },
  { id: "ps-107", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Es ist typisch für Experimentelle Studien, dass", options: ["mindestens zwei Variablen miteinander in einen Zusammenhang gebracht werden.", "sie im Kontext Schule und Unterricht stattfinden.", "sie vor allem beschreibend arbeiten.", "Kausalzusammenhänge überprüft werden."], correctIndices: [3] },
  { id: "ps-108", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Wenn ein Psychologe eine wissenschaftliche Untersuchung dazu macht, wie sich das Gedächtnis von Menschen im Verlauf des Erwachsenenalters verändert, so ist diese Arbeit dem folgenden Teilgebiet der Psychologie zuzuordnen:", options: ["Allgemeine Psychologie", "Entwicklungspsychologie", "Psychologie der Lernschwierigkeiten", "Klinische Psychologie"], correctIndices: [1] },
  { id: "ps-109", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Bei einer psychologischen Verhaltensbeobachtung steht die folgende wissenschaftliche Tätigkeit im Vordergrund:", options: ["Erklären", "Vorhersagen", "Bewerten", "Beschreiben"], correctIndices: [3] },
  { id: "ps-110", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Wie kann man entwicklungspsychologische Erkenntnisse systematisieren?", options: ["anhand des Informationsverarbeitungsansatzes", "anhand von Beobachtungen", "anhand von Längsschnittstudien", "anhand von beschreibenden Modellen, die nach Entwicklungsbereichen geordnet sind."], correctIndices: [3] },
  { id: "ps-111", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Welche der folgenden Aussagen benennt ein Kennzeichen der psychologischen Beobachtung?", options: ["Eine Beobachtung ist sorgfältig zu planen, z.B. indem das zu beobachtende Verhalten genau festgelegt wird.", "Das wichtigste bei der Beobachtung von Verhalten ist die Einfühlung in jedes einzelne Individuum, damit man auch die Motive und Gefühle erfasst.", "Eine Beobachtung ist immer möglichst offen zu halten, damit dem Beobachter nichts entgeht.", "Eine Beobachtung in der Psychologie beginnt immer mit einem auffälligen Ereignis, das neugierig macht."], correctIndices: [0] },
  { id: "ps-112", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Welche der unten angegebenen Prinzipien gehört NICHT zu den universellen Prinzipien der Entwicklungspsychologie?", options: ["Entwicklung ist geprägt durch Phasen schneller Veränderung und durch Plateaus.", "Eltern wissen am besten Bescheid, ob die Entwicklung ihres Kindes in die richtige Richtung und im richtigen Tempo vor sich geht.", "Entwicklung erfolgt bei allen Menschen einem genetisch angelegten \"Bauplan.\"", "Entwicklung folgt bei allen Menschen universell nach demselben Tempo."], correctIndices: [1] },
  { id: "ps-113", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Was ist charakteristisch für eine Längsschnittstudie?", options: ["eine Längsschnittstudie befasst sich mit der Entwicklung des Denkens.", "eine Längsschnittstudie gibt Alterstrends wider.", "eine Längsschnittstudie arbeitet mit wenigen Personen, dafür aber intensiv.", "eine Längsschnittstudie gibt Information über Entwicklungsverläufe."], correctIndices: [3] },
  { id: "ps-114", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Typisch für eine Querschnittsstudie ist, ...", options: ["... dass individuelle Entwicklungsverläufe quer über die Lebensphasen hinweg sichtbar werden.", "... dass Versuchspersonen ausfallen, weil sie die Testwiederholungen nicht mehr mitmachen wollen.", "... dass Versuchspersonen mehrfach befragt werden, um über die Altersphasen hinweg Information zu erhalten.", "... dass zu einem Zeitpunkt Personen unterschiedlichen Alters untersucht werden."], correctIndices: [3] },
  { id: "ps-115", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Das Modell der Entwicklungsaufgaben beruht auf", options: ["der Selbststeuerungstheorie", "der Milieutheorie", "der Reifungstheorie", "der Interaktionstheorie"], correctIndices: [3] },
  { id: "ps-116", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Es ist typisch für Kategorisierungsleistungen von Kindern in der Phase des formalen Denkens, dass sie", options: ["Gegenstände, die sie nicht kennen, gar nicht ordnen können.", "einfache Klassifikationen vornehmen können, diese aber nicht umkehren können.", "Gegenstände nach offensichtlichen Merkmalen ordnen können.", "Gegenstände differenziert und nach verschiedenen Gesichtspunkten ordnen können."], correctIndices: [3] },
  { id: "ps-117", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Ein Kind im Alter von 1 Jahr und 8 Monaten schlägt ein Bilderbuch auf, deutet mit dem Finger auf das Bild eines Hirschen und sagt: \"Kuh\". Nach Piaget kann man dieses Verhalten wie folgt interpretieren:", options: ["Kinder in der modernen Welt sind von Naturphänomenen entfremdet.", "Fehlendes Vorwissen und mangelhafter Wortschatz schränken Entwicklungsmöglichkeiten ein.", "Unangemessene Assimilation eines bekannten Schemas auf eine ähnliche Situation.", "Beispiel für drohende Vernachlässigung, weil das Kind mit dem Bilderbuch allein gelassen wird."], correctIndices: [2] },
  { id: "ps-118", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Welche Aussage ist für die Aufmerksamkeitsfunktion in der mittleren Kindheit (bis ca. 12 Jahre) richtig?", options: ["Aufmerksamkeit kann auf die wichtigen Aspekte einer Situation gelenkt werden.", "Die Aufmerksamkeitsspanne kann durch metakognitive Strategien noch nicht optimiert werden.", "Aufmerksamkeit ist überwiegend vom Willen und der Motivation abhängig.", "Die Aufmerksamkeitsspanne passt sich durch Übung dem 45 Minuten-Rhythmus der Schulstunden an."], correctIndices: [0] },
  { id: "ps-119", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Es ist typisch für Kategorisierungsleistungen von Kindern in der Phase des formalen Denkens, dass sie", options: ["Gegenstände, die sie nicht kennen, gar nicht ordnen können.", "einfache Klassifikationen vornehmen können, diese aber nicht umkehren können.", "Gegenstände differenziert und nach verschiedenen Gesichtspunkten ordnen können.", "Gegenstände nach offensichtlichen Merkmalen ordnen können."], correctIndices: [2] },
  { id: "ps-120", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Als Geschichtslehrer arbeiten Sie mit einem Text, in dem der Fall der Berliner Mauer aus mehreren Perspektiven betrachtet wird. Sie stellen dann die (hypothetische) Frage: \"Was wäre, wenn die Mauer bis heute nicht gefallen wäre?\" Wie ist diese Frage nach Piaget zu bewerten?", options: ["Kinder in der Phase der konkreten Operationen können diese Frage beantworten, wenn man sie mit Bild oder Video veranschaulicht.", "Jugendliche in der Phase des formal operatorischen Denkens können mit dieser hypothetischen Frage umgehen.", "Jugendliche in der Phase des formal operatorischen Denkens können mit der Frage nichts anfangen, weil sie unlogisch ist.", "Diese Frage fällt allen Schülerinnen und Schülern schwer, weil sie keinen Bezug mehr zur Mauer haben."], correctIndices: [1] },
  { id: "ps-121", subject: "psychologie", topic: "Lernstrategien", question: "Lehrer und Lehrerinnen können die Entwicklung der Metakognition fördern, indem sie", options: ["mehr Zeit lassen für Aufgaben.", "die Schülerinnen und Schüler in bestimmten Situationen konkret anregen, Lernstrategien einzusetzen.", "Schülerinnen und Schüler, die Wiederholungsstrategien anwenden, vor der Klasse besonders loben.", "den Schülerinnen und Schülern die Funktionen des Gedächtnisses erklären."], correctIndices: [1] },
  { id: "ps-122", subject: "psychologie", topic: "Gedächtnis", question: "Welche der folgenden Aussagen gibt die zentrale Aussage der Vergessenskurve am besten wieder?", options: ["Von dem Material, das vollständig gelernt wurde, wird das meiste sofort wieder vergessen.", "Material, das mit Interesse gelernt wurde, ist resistent gegen Vergessen.", "Material, das ein Lerner vollständig beherrscht, vergisst er nicht mehr.", "Je mehr Lernzeit ein Lerner aufwendet, desto langsamer vergisst er das Gelernte."], correctIndices: [0] },
  { id: "ps-123", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "In einem Experiment sollen Versuchspersonen eine Reihe von Begriffen lernen. Der Versuchsleiter erklärt vorab, worum es geht und bittet dann die Versuchspersonen, sich in einen der beiden Räume zu begeben, je nachdem, welche Versuchsbedingung ihnen angenehmer ist. Wie ist dieses Vorgehen aus forschungsmethodischer Sicht zu bewerten?", options: ["Das ist keine gute Idee, weil im Experiment die Versuchspersonen den Versuchsbedingungen nach Zufall zugeordnet werden müssen.", "Das ist eine gute Idee, weil so jeder seine Stärken unter den Versuchsbedingungen zeigen kann.", "Das ist eine gute Idee, weil sonst die Motivation der Versuchspersonen zu gering ist, sich anzustrengen.", "Das ist keine gute Idee, weil schon die Aussicht auf Belohnung das Ergebnis verfälschen kann."], correctIndices: [0] },
  { id: "ps-124", subject: "psychologie", topic: "Gedächtnis", question: "Eine Experimentalgruppe wird instruiert, sich eine Reihe von Bildern einzuprägen und diese in der Reihenfolge der Darbietung zu reproduzieren. Technisch gesprochen handelt es sich hierbei um", options: ["freie Reproduktion.", "Wiedererkennen von Gelerntem.", "Lernen von sinnfreiem Material.", "serielles Erinnern."], correctIndices: [3] },
  { id: "ps-125", subject: "psychologie", topic: "Unterricht & Klassenführung", question: "Wenn Sie als Lehrer oder Lehrerin eine Frage an Schüler und Schülerinnen stellen, empfiehlt es sich aus Sicht der kognitiven Lerntheorie", options: ["eine Wartezeit von 3-5 Sekunden einzuhalten, um den Schülern Zeit zur Informationsverarbeitung zu geben.", "diese Frage am besten in mehreren Varianten zu stellen, damit sich alle angesprochen fühlen können.", "die Frage so lange zu wiederholen, bis sie ein Schüler oder eine Schülerin beantworten kann.", "die Frage am besten gleich selbst zu beantworten."], correctIndices: [0] },
  { id: "ps-126", subject: "psychologie", topic: "Lernstrategien", question: "Organisationsstrategien als Lernstrategien", options: ["lernen Schüler und Schülerinnen in der Sekundarstufe besonders leicht.", "kommen bei Studierenden nicht mehr vor.", "spielen in der Schule keine Rolle.", "sind bereits bei Grundschulkindern spontan zu beobachten."], correctIndices: [0] },
  { id: "ps-127", subject: "psychologie", topic: "Lernstrategien", question: "Aus der Sicht der kognitiven Lerntheorien kann man zu Wiederholungsstrategien folgendes sagen:", options: ["Wiederholung stärkt das Behalten, wenn die Wiederholungen zeitlich verteilt werden und Pausen dazwischen eingelegt werden.", "Wiederholung ist für das Lernen in den Altersstufen nach der Grundschule unerheblich.", "Wiederholung ist als Lernstrategie in allen Altersstufen die beste Methode, um Lernstoff aufzunehmen.", "Wiederholung als Lernstrategie muss man Schülern und Schülerinnen nicht beibringen, da kommen sie selbst drauf."], correctIndices: [0] },
  { id: "ps-128", subject: "psychologie", topic: "Klassisches Konditionieren", question: "Beim Klassischen Konditionieren lernt ein Organismus", options: ["neue Auslösereize für einen vorhanden Reflex", "Angst zu haben", "Reize zu unterscheiden", "Reize zu generalisieren"], correctIndices: [0] },
  { id: "ps-129", subject: "psychologie", topic: "Klassisches Konditionieren", question: "Eine notwendige Voraussetzung für Klassisches Konditionieren ist es, dass", options: ["ein Reflex vorhanden ist.", "ein Verstärker vorhanden ist.", "ein interessanter Reiz vorhanden ist.", "Lernmotivation vorhanden ist."], correctIndices: [0] },
  { id: "ps-130", subject: "psychologie", topic: "Klassisches Konditionieren", question: "Wenn eine Person auf das Kindchenschema eine emotionale Reaktion zeigt, dann sind die Knopfaugen, Pausbacken und die Stupsnase aus der Sicht der Theorie des Klassischen Konditionierens", options: ["die neutralen Stimuli", "der konditionierte Reflex", "die generalisierte Reaktion", "die unkonditionierten Stimuli"], correctIndices: [3] },
  { id: "ps-131", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Die Grundannahme des Operanten Konditionierens ist am besten so beschrieben:", options: ["Lernen bei höheren Lebewesen ist die Folge von Einsicht.", "Verhaltensänderungen treten spontan auf und werden dann generalisiert.", "Lernen ist Verhaltensänderung aufgrund von Entwicklung.", "Verhaltensänderungen werden durch die Konsequenzen des Verhaltens beeinflusst."], correctIndices: [3] },
  { id: "ps-132", subject: "psychologie", topic: "Klassisches Konditionieren", question: "Das Phänomen der Reizgeneralisierung bei der Klassischen Konditionierung ist in folgendem Beispiel illustriert:", options: ["Ein Kind hat plötzlich Angst vor einem Schmusetier, das vorher sein Lieblingstier war.", "Eine Katze befreit sich immer wieder aus einem Käfig, wenn sie einmal den Hebelmechanismus dazu gefunden hat.", "Ein Mädchen hat ein Kaninchen mit Angst assoziiert und als Folge davon hat sie auch Angst vor dem Nerzmantel der Mutter.", "Ein Hund speichelt auf die Töne eines Metronoms, aber nicht auf das Leuchten einer Glühbirne."], correctIndices: [2] },
  { id: "ps-133", subject: "psychologie", topic: "Klassisches Konditionieren", question: "Die Theorie des Klassischen Konditionierens sagt vorher, dass Löschung eintritt, wenn", options: ["die Häufigkeit, mit der die konditionierte Reaktion verstärkt wird, abnimmt.", "der Organismus durch den konditionierten Reiz gesättigt ist.", "der konditionierte Reiz nur noch ohne den unkonditionierten Reiz dargeboten wird.", "eine Person den Mechanismus der Reiz-Reaktions-Verbindung durchschaut hat."], correctIndices: [2] },
  { id: "ps-134", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Was ist ein Beispiel für einen informativen Verstärker?", options: ["Eine knappe Bemerkung des Lehrers: \"Richtig!\"", "Eine glatte Aufgabenlösung, die unmittelbar einleuchtet und für den Lerner erkennbar funktioniert.", "Eine ausführliche Liste über Stärken und Schwächen einer Arbeit, die der Lehrer zurückgibt.", "Das Lächeln der Lehrerin, weil dann der Schüler weiß, dass er etwas richtig gemacht hat."], correctIndices: [1] },
  { id: "ps-135", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Das Prinzip der intermittierenden Verstärkung beruht darauf, dass", options: ["Aktivitätsverstärker eingesetzt werden.", "Fremdverstärkung eingesetzt wird.", "Verstärker unregelmäßig eingesetzt werden.", "unerwünschtes Verhalten ignoriert wird."], correctIndices: [2] },
  { id: "ps-136", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Wenn ein Wissenschaftler ein Versuchstier dazu bringen will, ein neues Verhalten zu lernen, dann ist der folgende Verstärkungsplan sinnvoll:", options: ["Immerverstärkung", "Intervallverstärkung", "intermittierende Verstärkung", "Bestrafung"], correctIndices: [0] },
  { id: "ps-137", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Welche Aussage über Verstärker ist aus der Sicht der Theorie des Operanten Konditionierens richtig?", options: ["Verstärker sind bedeutungslos, sobald eine Person zur Einsicht in das richtige Verhalten fähig ist.", "Wenn positive Verstärkung eingesetzt wird, tritt früher oder später der Verwöhneffekt auf.", "Verstärkung von außen hat den gewünschten verhaltensformenden Effekt nur bis zur Pubertät.", "Soziale Verstärker, z.B. Vergabe bestimmter Privilegien, können zur Verhaltensformung genutzt werden."], correctIndices: [3] },
  { id: "ps-138", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Programmiertes Lernen aus der Sicht des operanten Konditionierens hat die folgenden Merkmale:", options: ["Der Lernstoff wird in kleine Einheiten zerlegt.", "Richtige Reaktionen werden zeitlich verzögert verstärkt.", "Der Lernstoff wird über ein Softwareprogramm vermittelt.", "Der Lehrer bestimmt das Lerntempo (Außensteuerung!)."], correctIndices: [0] },
  { id: "ps-139", subject: "psychologie", topic: "Konditionieren & Lernen", question: "Wenn eine Lehrerin den Schülerinnen und Schülern einen lustigen Stempel in das Heft macht, wenn eine Lösung besonders gut gelungen ist, so ist das aus der Sicht der Theorie des operanten Konditionierens", options: ["kindischer Firlefanz.", "eine Verwöhnung.", "ein sekundärer Verstärker.", "eine konditionierte Reaktion."], correctIndices: [2] },
  { id: "ps-140", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Welche Aspekte unterscheidet Sternberg in seiner Intelligenz-Theorie?", options: ["Interpersonale, Intrapersonale und naturalistische Intelligenz", "Kristalline und fluide Intelligenz", "7 Primärfaktoren der Intelligenz, z.B. Wortflüssigkeit und logisches Schlussfolgern", "Analytische, Kreative und Praktische Intelligenz"], correctIndices: [3] },
  { id: "ps-141", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Cattell charakterisiert die Kristalline Intelligenz als", options: ["die besondere Fähigkeit, schnell neue Information aufzufassen und umzusetzen.", "die mit dem Alter zunehmende Starrheit des Denkens.", "die Fähigkeit, besonders schnell und effektiv auf vorhandenes Wissen zuzugreifen.", "die bei Kindern beobachtbare, klare Denksweise"], correctIndices: [2] },
  { id: "ps-142", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Welcher Faktor gehört nach Thurstone zu den Primärfaktoren der Intelligenz?", options: ["Generalfaktor s", "Wortflüssigkeit", "Fluide Intelligenz", "Interpersonale Intelligenz"], correctIndices: [1] },
  { id: "ps-143", subject: "psychologie", topic: "Persönlichkeitspsychologie", question: "Welche Aussage über Persönlichkeitsmerkmale ist korrekt?", options: ["Persönlichkeitsmerkmale haben immer mit Intelligenz zu tun.", "Persönlichkeitsmerkmale sind über Situationen hinweg stabil.", "Persönlichkeitsmerkmale spielen für den Schulerfolg keine Rolle.", "Persönlichkeitsmerkmale sind angeboren."], correctIndices: [1] },
  { id: "ps-144", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Wenn Schüler und Schülerinnen einen misserfolgsorientierten Attributionsstil haben, ist die folgende Konsequenz zu erwarten:", options: ["Die Bereitschaft, sich anzustrengen, wird nach Misserfolg zunehmen.", "Sie werden sich Hilfe holen, um den nächsten Misserfolg zu verhindern.", "Sie werden allmählich verstehen, dass sie für ihren Misserfolg selbst verantwortlich sind.", "Die Bereitschaft, sich anzustrengen, wird nach Misserfolg weiter abnehmen."], correctIndices: [3] },
  { id: "ps-145", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Wenn Schülerinnen und Schüler, die von sich keine guten Leistungen erwarten und geringes Vertrauen in ihre Fähigkeiten haben, sich für eine Aufgabe Ziele setzen sollen, dann gehen sie wahrscheinlich so vor:", options: ["Sie setzen sich realistische Ziele.", "Sie setzen sich sehr hohe Ziele.", "Sie setzen sich mehrere Ziele.", "Sie bitten den Lehrer, die Ziele vorzugeben."], correctIndices: [1] },
  { id: "ps-146", subject: "psychologie", topic: "Lernschwierigkeiten", question: "Am Verhalten von Kindern mit Lernschwierigkeiten ist zu beobachten, dass sie", options: ["sich schon über kleine Erfolge freuen.", "Fehler als Lernmöglichkeit ansehen.", "Misserfolge der eigenen mangelnden Begabung zuschreiben.", "sich Hilfe holen, um weiterzukommen."], correctIndices: [2] },
  { id: "ps-147", subject: "psychologie", topic: "Bewertung & Bezugsnormen", question: "Wenn ein Schüler mit seinen Leistungen die sachliche Bezugsnorm verfehlt, dann", options: ["sind seine aktuellen Leistungen im Vergleich zu seiner bisherigen Leistung abgefallen.", "sind seine Leistungen nicht altersgemäß.", "entsprechen seine Leistungen nicht den Mindeststandards der Schule.", "sind seine Leistungen schlechter als die der anderen in seiner Klasse."], correctIndices: [2] },
  { id: "ps-148", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Zu den Folgesymptomen von Aufmerksamkeitsstörungen und Hyperaktivität gehört", options: ["Depression im Jugendalter.", "Motivationale Impulsivität.", "Abnehmende Lernmotivation.", "Sozialer Rückzug."], correctIndices: [2] },
  { id: "ps-149", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Für die Diagnostik von ADHS gilt, dass", options: ["die Symptomatik in zwei Lebensbereichen nachgewiesen werden muss.", "Leistungsschwankungen schon ein erster Hinweis auf ADHS sind.", "die Diagnose-Erstellung ein halbes Jahr dauert.", "der Lehrer oder die Lehrerin nichts damit zu tun hat."], correctIndices: [0] },
  { id: "ps-150", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Zur Förderung von Kindern und Jugendlichen mit ADHS hat es sich bewährt,", options: ["konkret mit ihnen an Strategien zu arbeiten, sich und ihre Arbeit zu organisieren.", "sie ganz hinten im Klassenzimmer zu platzieren, damit sie niemanden stören.", "sie in eine Schulart weiterzuempfehlen, die leichter ist als die aktuelle.", "ihnen dieselben Aufgaben zu geben, wie allen anderen, damit sie sich nicht benachteiligt fühlen."], correctIndices: [0] },
  { id: "ps-151", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Schülerinnen und Schüler mit einem erfolgsorientierten Attributionsstil zeichnen sich dadurch aus, dass...", options: ["sie Erfolge mit der eigenen Anstrengung erklären.", "sie konsequent auf ihr Glück vertrauen.", "sie Misserfolge ignorieren und zuhause verschweigen.", "sie sich schon über kleinste Erfolge freuen können."], correctIndices: [0] },
  { id: "ps-152", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Das Prinzip der Reattributionstrainings besteht darin, dass", options: ["Schüler ihre Erfolge mit ihrer Anstrengung erklären.", "Schüler mit ihren Misserfolgen konfrontiert werden, um ihnen zu zeigen, dass sie sich mehr anstrengen müssen.", "Schüler getröstet werden und ihnen gezeigt wird, dass man auch mal Glück haben kann.", "Schüler mehr Übungszeit bekommen als andere, wenn sie Lernschwierigkeiten haben."], correctIndices: [0] },
  { id: "ps-153", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Es ist ein typisches Ergebnis von Reattributionstrainings, dass", options: ["Schüler lernen, auch mal auf ihr Glück zu vertrauen.", "bei Schülern die Überzeugung wächst, dass sie ihren Schulerfolg kontrollieren können.", "die Schüler einsehen, dass Begabung der wichtigste Faktor für Schulerfolg ist.", "die Schüler Misserfolge weniger ernst nehmen."], correctIndices: [1] },
  { id: "ps-154", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Was ist die Aufgabe der Pädagogischen Psychologie?", options: ["Erhaltung der seelischen Gesundheit von Menschen.", "Ausbildung von Therapeuten.", "Beschreiben, erklären, vorhersagen und beeinflussen von Verhalten.", "Unterstützung von Lehrerinnen und Lehrern sowie Erziehern in Fragen der Erziehung von Kindern und Jugendlichen."], correctIndices: [3] },
  { id: "ps-155", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Eine Meta-Analyse zeichnet sich dadurch aus, dass", options: ["eine Vielzahl von Studien zum selben Thema im Überblick ausgewertet werden.", "mehrere Experten gemeinsam daran arbeiten.", "übergeordnete Gesichtspunkte und gesellschaftliche Relevanz die Themen bestimmen.", "vor allem Fehler in den Untersuchungen kritisch hinterfragt werden."], correctIndices: [0] },
  { id: "ps-156", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Welche der unten angegebenen Prinzipien gehört NICHT zu den universellen Prinzipien der Entwicklungspsychologie?", options: ["Entwicklung ist geprägt durch Phasen schneller Veränderung und durch Plateaus.", "Entwicklung erfolgt bei verschiedenen Menschen in unterschiedlichem Tempo.", "Eltern wissen am besten Bescheid, ob die Entwicklung ihres Kindes in die richtige Richtung und im richtigen Tempo vor sich geht.", "Entwicklung beinhaltet Wachstum ebenso wie Stagnation und Verluste."], correctIndices: [2] },
  { id: "ps-157", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Welche der folgenden Aussagen gilt als ein universelles Entwicklungsprinzip?", options: ["Entwicklungsförderung ist Sache sowohl der Eltern als auch der Lehrerinnen und Lehrer.", "Die Veränderung in einzelnen Entwicklungsbereichen ist bei verschiedenen Menschen unterschiedlich schnell.", "Es gibt in der Entwicklung von Kindern und Jugendlichen kein \"zu früh\" oder \"zu spät\"; alle Menschen kommen in ihrem Tempo an ein Ziel.", "Entwicklungspsychologie kann keinen universellen Prinzipien folgen, weil jeder Mensch anders ist."], correctIndices: [1] },
  { id: "ps-158", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Als Entwicklungsbereich im Sinne der Entwicklungspsychologie gilt:", options: ["Wissen in den Schulfächern", "Sprachliche Ausdrucksfähigkeit.", "Begabungsunterschiede", "Lerngeschwindigkeit"], correctIndices: [1] },
  { id: "ps-159", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Die Gütekriterien, die eine wissenschaftliche Beobachtung erfüllen muss, sind", options: ["Allgemeingültigkeit, Verständlichkeit und Genauigkeit", "Objektivität, Reliabilität und Validität", "Subjektivität, Relativität und Individualität", "Transparenz, Nützlichkeit und Datenschutz"], correctIndices: [1] },
  { id: "ps-160", subject: "psychologie", topic: "Wissenschaftliche Methoden", question: "Zur Sicherung der Gütekriterien von Beobachtungen sind folgende Maßnahmen sinnvoll:", options: ["die zu beobachtenden Personen erstmal genau kennen lernen", "zu kritischen Zeiten grundsätzlich nicht beobachten, z.B. freitags vor Schulschluss", "gezielt Ereignis- oder Zeitstichproben nehmen", "möglichst \"naive\" Beobachterinnen und Beobachter einsetzen"], correctIndices: [2] },
  { id: "ps-161", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Wenn man feststellt, dass Menschen bestimmte Fertigkeiten in einem gewissen Zeitfenster schneller lernen als zu anderen Zeiten, so nennt man dieses Zeitfenster", options: ["eine sensible Phase", "einen Risikofaktor", "eine Disposition", "eine Ressource"], correctIndices: [0] },
  { id: "ps-162", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Schülerinnen und Schüler, die in der Lage sind, sich vorzustellen, dass Dinge ganz anders wären, als sie sind, sind nach Piaget wahrscheinlich in der Phase", options: ["des präoperativen Denkens", "der konkreten Operationen", "der formalen Operationen", "der Informationsverarbeitung"], correctIndices: [2] },
  { id: "ps-163", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Welchen der folgenden Aspekte der Kritik an der Theorie Piagets ist aus forschungsmethodischer Sicht besonders relevant?", options: ["Die Befragungsmethode setzt gut ausgebaute Sprachfertigkeiten bei den Kindern voraus.", "Die Stichproben beziehen keine Personen ein, die älter sind als 18 Jahre.", "Die experimentellen Aufgaben sind nicht kindgerecht.", "Es fehlen Längsschnittstudien."], correctIndices: [0] },
  { id: "ps-164", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Welche der folgenden Faktoren spielen aus der Sicht der Informationsverarbeitungstheorie eine förderliche Rolle für die Entwicklung des Denkens im mittleren Kindesalter (bis ca. 12 Jahre)?", options: ["die zunehmende Lerngeschwindigkeit", "Die Fähigkeit, Aufmerksamkeit zu steuern", "die wachsende Willenskraft", "der Schuleintritt und der formale Unterricht"], correctIndices: [1] },
  { id: "ps-165", subject: "psychologie", topic: "Lernstrategien", question: "Aus der Grundschulzeit bringen die Schülerinnen und Schüler wahrscheinlich die folgende Lernstrategie mit:", options: ["Wiederholungsstrategien", "Organisationsstrategien", "Selbstkontrollstrategien", "Abgucken und Spickzettel schreiben"], correctIndices: [0] },
  { id: "ps-166", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Das entscheidende Moment bei der Assimilation im Sinne Piagets ist, dass", options: ["das Individuum vorhandene Schemata so verändert, dass es sich den Umweltgegebenheiten anpasst.", "das Individuum abstrakte Regeln aus einem Versuchs- und Irrtumsverhalten erkennt.", "das Individuum bekannte Schemata und Verhaltensweisen auf neue Objekte überträgt.", "das Individuum gedanklich Hypothesen aufstellen und prüfen kann."], correctIndices: [2] },
  { id: "ps-167", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Welcher der folgenden Sätze hat die Form einer prüfbaren Hypothese, die sich für ein psychologisches Experiment eignet?", options: ["Mit Hilfe der Mind-Map Technik lernen alle Schülerinnen und Schüler schneller und nachhaltiger.", "Fördert die Mind-Map Technik die Lernqualität?", "Die Mind-Map Technik verändert bei richtiger Anwendung die Lebenszufriedenheit.", "Die Mind-Map Technik steigert die Zahl der Lösungsvorschläge in Problemlöseaufgaben."], correctIndices: [3] },
  { id: "ps-168", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Ein Wissenschaftler untersucht die Behaltensleistung: Versuchspersonen lernen Listen von 20 Begriffen (10 konkret, 10 abstrakt). Geprüft wird, ob konkrete Begriffe schneller eingeprägt und länger behalten werden. Was ist / sind im Experiment die abhängige(n) Variable(n)?", options: ["Abstraktheit und Konkretheit", "Behaltensdauer und Lernzeit", "Alter und Tageszeit", "Begriffe und Behaltensleistung"], correctIndices: [1] },
  { id: "ps-169", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Eine Wissenschaftlergruppe hat untersucht, welche Lernbedingungen für Schülerinnen und Schüler der 6. Klassen günstig sind (Bilder, Grafiken, Text, alles zusammen) und den Lernerfolg in einem Wissenstest erfasst. Was ist in diesem Experiment die unabhängige Variable?", options: ["die Bilder", "der Lernerfolg", "das Alter der Kinder", "die Text-Bild-Kombination"], correctIndices: [3] },
  { id: "ps-170", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Wissenschaftler möchten überprüfen, ob die Mind-Map-Technik die Kreativität bei Problemlöseaufgaben fördert (zwei Gruppen mit/ohne Technik, ausgewertet nach Zahl und Originalität der Lösungsvorschläge). Was sind die unabhängige und die abhängige Variable?", options: ["Die unabhängige Variable ist die Technik (Mindmap vs. alternative Technik), eine abhängige Variable ist die Zahl der Lösungsvorschläge.", "Die unabhängige Variable ist die verwendete Technik, die abhängige Variable ist die Gruppe.", "Dieses Experiment hat weder eine unabhängige noch eine abhängige Variable, alles hängt zusammen.", "Die unabhängige Variable ist die Gruppe und die abhängige Variable die Zahl der Lösungsvorschläge."], correctIndices: [0] },
  { id: "ps-171", subject: "psychologie", topic: "Gedächtnis", question: "Ein typischer Inhalt des episodischen Gedächtnisses ist folgendes:", options: ["Jemand kann ein Ereignis aus seinem eigenen Leben rekonstruieren, z.B. erste Tanzstunde.", "Jemand weiß genau, was in welcher Episode einer Serie passiert ist.", "Jemand kann genau wiedergeben, was in der letzten Sekunde passiert ist.", "Die Erinnerung an ein Detail, das man vorher nicht abgespeichert hatte."], correctIndices: [0] },
  { id: "ps-172", subject: "psychologie", topic: "Gedächtnis", question: "Zur Optimierung des Arbeitsgedächtnisses ist folgendes Vorgehen zielführend:", options: ["Elemente zusammenfassen und miteinander zu größeren Einheiten verknüpfen, sog. Chunking.", "Anzahl der Elemente, die gleichzeitig bearbeitet werden müssen, eingrenzen.", "Sensorisches Gedächtnis begrenzen.", "Pausen einlegen und Wiederholungen einplanen."], correctIndices: [0] },
  { id: "ps-173", subject: "psychologie", topic: "Lernstrategien", question: "Wiederholungsstrategien sind effektiv, wenn man darauf achtet,...", options: ["den Stoff möglichst wörtlich zu memorieren", "sich möglichst zeitnah abfragen zu lassen", "das Lernen auf mehrere Tage zu verteilen", "nicht zu früh vor der Klausur damit anzufangen, 1-2 Tage sind ideal"], correctIndices: [2] },
  { id: "ps-174", subject: "psychologie", topic: "Lernstrategien", question: "Ein Beispiel für den Einsatz von Organisationsstrategien wäre:", options: ["Schreibtisch aufräumen und Ordnung machen", "sich mit Mitschülerinnen und Mitschülern verabreden, wer welche Aufgaben macht", "Information ordnen, kategorisieren, strukturieren", "überlegen, was man schon zum Thema weiß"], correctIndices: [2] },
  { id: "ps-175", subject: "psychologie", topic: "Lernstrategien", question: "Welche der folgenden Vorgehensweisen wäre ein Beispiel für Elaborationsstrategien?", options: ["Eigene Beispiele zu den Prinzipien suchen, die man gelernt hat", "Ähnliche Aufgaben immer und immer wieder durchführen, um Routine zu gewinnen", "Positiv/negativ-Listen anfertigen und die wichtigsten Punkte eines Textes einander gegenüberstellen", "aus einem Text eine Gliederung herausarbeiten"], correctIndices: [0] },
  { id: "ps-176", subject: "psychologie", topic: "Lernstrategien", question: "Über Visualisierungstechniken kann man folgendes sagen:", options: ["Sie machen das Lernen bunter und sind eine nette Abwechslung, wenn man Zeit dafür hat.", "Sie erleichtern das Verständnis von Beziehungen zwischen verschiedenen Informations- und Wissensbeständen.", "Sie eignen sich besonders für das Lernen in den Naturwissenschaften.", "Sie helfen nur künstlerisch begabten Menschen beim Lernen."], correctIndices: [1] },
  { id: "ps-177", subject: "psychologie", topic: "Modelllernen", question: "Welches der folgenden Merkmale führt dazu, dass ein Modell mit hoher Wahrscheinlichkeit nachgeahmt wird? Das Modell ist ....", options: ["moralisch", "berühmt", "männlich", "sozial angesehen"], correctIndices: [3] },
  { id: "ps-178", subject: "psychologie", topic: "Modelllernen", question: "Ausgangspunkt dafür, dass Schüler am Modell lernen, ist", options: ["Die Einsicht, dass man etwas nicht kann, was ein anderer schon kann.", "die Fähigkeit, die Aufmerksamkeit auf das Zielverhalten zu lenken.", "Das Zielverhalten als korrekt erkannt zu haben.", "Die Bereitschaft, sich etwas abzuschauen."], correctIndices: [1] },
  { id: "ps-179", subject: "psychologie", topic: "Modelllernen", question: "Welches Zielverhalten eignet sich für das Lernen am Modell?", options: ["Kontrolle von Emotionen", "Ausdruck von Emotionen", "Ehrgeiz und Anstrengungsbereitschaft", "in Ruhe Nachdenken"], correctIndices: [1] },
  { id: "ps-180", subject: "psychologie", topic: "Modelllernen", question: "In welchen Bereichen schulischen Lernens spielt das Lernen am Modell wahrscheinlich KEINE Rolle?", options: ["Interesse an Naturwissenschaften", "Bewegungslernen, z.B. im Sport oder in der Musik", "Lernstrategien und Lernverhalten", "prosoziales Verhalten im Umgang miteinander"], correctIndices: [0] },
  { id: "ps-181", subject: "psychologie", topic: "Statistik", question: "Für ein normalverteiltes Persönlichkeitsmerkmal gilt:", options: ["Im Bereich von plus/minus einer Standardabweichung um den Mittelwert liegen etwa 34% aller Personen.", "Im Bereich von plus/minus zwei Standardabweichung um den Mittelwert liegen etwa 95 % aller Personen.", "Die Anzahl der Fälle oberhalb des arithmetischen Mittels ist größer als die Anzahl der Fälle unterhalb des arithmetischen Mittels.", "Oberhalb des Mittelwerts plus zwei Standardabweichungen liegen etwa 5 % aller Personen."], correctIndices: [1] },
  { id: "ps-182", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Die Theorie von Thurstone geht von folgenden Annahmen aus:", options: ["Es gibt einen Generalfaktor der Intelligenz plus mehrere spezifische, aber weniger bedeutsame Faktoren", "Es gibt drei Aspekte der Intelligenz, nämlich Analytische, kreative und praktische Intelligenz", "Es gibt fluide und kristalline Intelligenz", "Intelligenz ist multifaktoriell und enthält Faktoren wie Wortflüssigkeit, räumliches Vorstellungsvermögen, Gedächtnis, Analoges Schlussfolgern"], correctIndices: [3] },
  { id: "ps-183", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Eine Feldstudie zeichnet sich dadurch aus, dass...", options: ["Versuchspersonen nach Zufall ausgewählt werden.", "besonders große Stichproben untersucht werden.", "die Ergebnisse besonders gut generalisiert werden können.", "die Probanden in ihrer natürlichen Umgebung untersucht werden."], correctIndices: [3] },
  { id: "ps-184", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Es ist typisch für eine Feldstudie, dass...", options: ["sie in der Schule stattfindet.", "sie die Menschen in ihrem natürlichen Umfeld manipuliert.", "die Merkmale so erhoben werden, wie man sie vorfindet.", "sie Ursache-Wirkungszusammenhänge ergründen."], correctIndices: [2] },
  { id: "ps-185", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Welche Fragestellung eignet sich für eine Feldstudie?", options: ["Wie verändert die Vertrautheit mit einer Sprache die Reaktionszeit auf Abweichungen von der Grammatik in der gesprochenen Sprache?", "Ist die Verteilung der Aufmerksamkeit beim Lesen für alle Wortarten gleich?", "Sind Schülerinnen und Schüler, die ein Instrument spielen oder im Sportverein aktiv sind, in den schulischen Leistungen stärker als diejenigen, die es nicht sind?", "Schneiden Schülerinnen und Schüler in Aufmerksamkeitstests besser ab, wenn sie vorher 5 Minuten motorische Geschicklichkeitsübungen machen?"], correctIndices: [2] },
  { id: "ps-186", subject: "psychologie", topic: "Statistik", question: "Eine Korrelation macht eine Aussage über...", options: ["Ursache und Wirkung-Verhältnisse", "Entwicklungsbedingungen", "Zusammenhänge zwischen Variablen", "Lernergebnisse"], correctIndices: [2] },
  { id: "ps-187", subject: "psychologie", topic: "Statistik", question: "Eine negative Korrelation liegt vor, wenn...", options: ["eine Variable einen unerwünschten Einfluss auf eine andere hat, z.B. Schulangst auf die Leistung", "Ungleichheiten zementiert werden, z.B. Korrelation zwischen sozioökonomischem Status der Eltern und Schulempfehlung", "zwei Variablen gegenläufig assoziiert sind, z.B. Prüfungsängstlichkeit und Leistung", "zwei Variablen so assoziiert sind, dass sie sich beide jeweils in die negative Richtung entwickeln"], correctIndices: [2] },
  { id: "ps-188", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Welche Aussage über die Rolle von Zielen für die Bereitschaft, sich im Unterricht anzustrengen, ist durch die Befunde der Motivationspsychologie belegt?", options: ["Wenn Schülerinnen und Schüler das Ziel des Unterrichts nicht kennen, sind sie besonders neugierig darauf, worauf das Geschehen hinauslaufen wird.", "Wenn Schülerinnen und Schüler völlig frei entscheiden können, wie lange sie sich mit einer Sache beschäftigen, wird das Ergebnis besonders gehaltvoll.", "Schüler und Schülerinnen erzielen bessere Ergebnisse, wenn sie klare Zielvorgaben erhalten.", "Schüler und Schülerinnen erzielen die besten Ergebnisse, wenn sie nicht durch Zielvorgaben eingeengt werden."], correctIndices: [2] },
  { id: "ps-189", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Welche Aussage über Interesse ist auf der Basis der motivationspsychologischen Forschung zutreffend?", options: ["Das Interesse an einem Fach ist bei Schülerinnen und Schülern über längere Zeit stabil.", "Ob sich ein Schüler oder eine Schülerin am Unterricht beteiligt, hängt hauptsächlich vom Interesse ab.", "Ob in einer Unterrichtsstunde Interesse geweckt wird, hängt vom Anreizwert der Situation ab.", "Am Interesse der Schülerinnen und Schüler können Lehrer und Lehrerinnen wenig ändern."], correctIndices: [2] },
  { id: "ps-190", subject: "psychologie", topic: "Motivation & Zielorientierung", question: "Lernzielorientierung liegt vor, wenn Schülerinnen und Schüler...", options: ["gerade so das allernötigste für den Unterricht tun.", "jede Gelegenheit wahrnehmen zu zeigen, dass sie der/die Beste sind.", "versuchen, Fehler zu vermeiden und Schwächen zu verbergen.", "bei Schwierigkeiten an einer Sache dran bleiben."], correctIndices: [3] },
  { id: "ps-191", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Welche der folgenden Umschreibungen trifft am ehesten zu? Attribution ist...", options: ["eine Entschuldigung für Misserfolg.", "eine positive Verstärkung.", "ein hypothetisches Konstrukt.", "eine Ursachenzuschreibung für einen Erfolg oder Misserfolg, den man erlebt hat."], correctIndices: [3] },
  { id: "ps-192", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Um bei Schülerinnen und Schülern die Erfolgsorientierung zu stärken, können Lehrerinnen und Lehrer...", options: ["erfolgreiche Schülerinnen und Schüler besonders loben, so dass es die anderen auch mitbekommen.", "betonen, dass Erfolge auch vom Glück abhängen.", "hervorheben, dass nicht jeder in allen Dingen gut sein kann.", "einzelnen Lernern individuelle Fortschritte aufzeigen."], correctIndices: [3] },
  { id: "ps-193", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Misserfolgsorientierung liegt bei einer Person wahrscheinlich vor, wenn sie...", options: ["viel Lernzeit in die Vorbereitung einer Prüfung investiert.", "in der Prüfungssituation nicht zeigen kann, was sie gelernt hat.", "sich bei einem Erfolg freut, dass sie Glück gehabt hat.", "mehrere Misserfolge erleben muss, bevor sie das Lernverhalten ändert."], correctIndices: [2] },
  { id: "ps-194", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Was ist im Experiment zur Frage, ob (knall)buntes Papier das Arbeitsverhalten von Kindern mit Aufmerksamkeitsstörungen beeinflusst (Imhof, 1995), die Unabhängige Variable?", options: ["die Farbigkeit des Schreibpapiers (weiß vs. bunt).", "die Zeit in Sekunden, die die Schülerinnen und Schüler zum Abschreiben der Texte benötigen.", "die Anzahl der Rechtschreibfehler beim Abschreiben.", "die feinmotorische Kontrolle."], correctIndices: [0] },
  { id: "ps-195", subject: "psychologie", topic: "ADHS & Verhaltensauffälligkeiten", question: "Wenn im Experiment Schülerinnen und Schüler mit einer Diagnose ADHS mit Schülerinnen und Schülern ohne Diagnose verglichen werden, dann ist die ADHS-Diagnose...", options: ["eine unzulässige Stigmatisierung.", "eine quasi-experimentelle Variable.", "eine Störvariable.", "eine Ausrede für das Privileg, auf buntem Papier zu schreiben."], correctIndices: [1] },
  { id: "ps-196", subject: "psychologie", topic: "Modelllernen", question: "Ein Modell wird umso wahrscheinlicher nachgeahmt,", options: ["je aggressiver es ist.", "je mehr sich der Beobachter mit ihm identifiziert.", "je älter es ist.", "je mehr es kann."], correctIndices: [1] },
  { id: "ps-197", subject: "psychologie", topic: "Modelllernen", question: "Sie möchten, dass die Schüler und Schülerinnen Ihrer Klasse lernen, ein gutes Referat zu halten. Aus der Sicht der Theorie des Lernens am Modell wäre folgendes eine sinnvolle Maßnahme:", options: ["Sie lassen einzelne Schüler und Schülerinnen kleine Präsentationen machen und arbeiten mit der Klasse heraus, wie und was gelungen war.", "Sie halten der Klasse selbst eine beispielhaft vorbereitete Präsentation: So, und jetzt nachmachen!", "Sie lassen einen Schüler ein Referat halten und kritisieren es dann ausführlich mit der Klasse.", "Sie spielen der Klasse ein Video einer gelungenen Rede eines Prominenten vor."], correctIndices: [0] },
  { id: "ps-198", subject: "psychologie", topic: "Konditionieren & Lernen", question: "In der sozial kognitiven Lerntheorie von Bandura spielt im Gegensatz zur Theorie des operanten Konditionierens", options: ["Bestrafung keine Rolle.", "der Einsatz von Lernstrategien eine Rolle.", "das Beobachten von einem Modell eine Rolle.", "Verstärkung keine Rolle."], correctIndices: [2] },
  { id: "ps-199", subject: "psychologie", topic: "Attribution & Reattributionstraining", question: "Ein Re-Attributionstraining beginnt damit, dass der Lehrer oder die Lehrerin", options: ["den Attributionsstil eines Schülers im Gespräch erkundet.", "dem Schüler die Folgen seines Misserfolgs vor Augen hält.", "die Eltern darauf hinweist, das Kind mehr zu loben.", "positive Attributionen als Modell vormacht."], correctIndices: [0] },
  { id: "ps-200", subject: "psychologie", topic: "Piaget: Kognitive Entwicklung", question: "Ein Schüler hat im Deutschunterricht gelernt, wie man sich aus Sachtexten Information erschließt, im Englischunterricht dagegen nur die wörtliche Übersetzung geübt. An der Uni bringt er zu einem englischen Fachtext eine Wort-für-Wort-Übersetzung mit statt der zentralen Information. Was ist - in der Begrifflichkeit von Piaget - passiert?", options: ["Es liegt eine Akkommodation des Schemas aus dem Deutschunterricht vor.", "Es liegt eine falsche Assimilation des Schemas aus dem Englischunterricht der Schule vor.", "Der Student ist schlicht überfordert von der Aufgabe.", "Es liegt ein Missverständnis seitens der Dozentin vor."], correctIndices: [1] },
  { id: "ps-201", subject: "psychologie", topic: "Entwicklungspsychologie: Grundlagen", question: "Ein 11-jähriges Mädchen möchte, dass ihre Eltern sie in einer Fußballmannschaft anmelden, nachdem sie im Sportunterricht Spaß an Bällen entdeckt und von einer Freundin von der Mannschaft gehört hat. Wie erklärt man dieses Verhalten aus Sicht erklärender entwicklungspsychologischer Modelle am ehesten?", options: ["Entwicklung ist ein Ergebnis aus Reifung, Umwelteinfluss und Selbststeuerung", "Entwicklung ist ein Ergebnis von Umwelteinflüssen (Sportunterricht, Freundin)", "Entwicklung ist ein Ergebnis von Selbststeuerung (das Mädchen geht von sich aus auf die Eltern zu)", "Entwicklung ist ein Ergebnis von Reifung der genetisch festgelegten Anlagen (sportliche Fähigkeit)"], correctIndices: [0] },
  { id: "ps-202", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "In welcher Phase erarbeiten die Schüler im Gruppenpuzzle die thematischen Inhalte?", options: ["Einführungsphase", "Expertengruppenphase", "Vermittlungsphase", "Stammgruppenphase"], correctIndices: [1] },
  { id: "ps-203", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "In einem Gruppenpuzzle bedeutet „positive Interdependenz“, dass", options: ["ein sozialer Austausch erforderlich ist, um gemeinsame Ziele zu erreichen.", "sich alle gegenseitig helfen und sich bei der Bearbeitung der verschiedenen Themen unterstützen.", "kein einzelner für das Funktionieren der Gruppe verantwortlich gemacht wird", "sich die Leistungserwartungen am schwächsten Gruppenmitglied orientieren."], correctIndices: [0] },
  { id: "ps-204", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Die Untersuchung von Borsch et al. (2002) zum Gruppenpuzzle ist methodisch gesehen", options: ["eine Korrelationsstudie", "ein Laborexperiment", "ein Feldexperiment", "eine Querschnittsstudie"], correctIndices: [2] },
  { id: "ps-205", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Die Abhängige Variable in der Studie von Borsch et al. (2002) ist", options: ["das kooperative Lernen", "der Abbau von Vorurteilen", "das Alter der Probanden", "der Wissenszuwachs im Thema"], correctIndices: [3] },
  { id: "ps-206", subject: "psychologie", topic: "Sozialpsychologie", question: "Aus der Perspektive der Sozialen Kognition als Teilgebiet der Sozialpsychologie wird die folgende Forschungsfrage relevant:", options: ["Welche Rolle spielt die Zusammensetzung der Klasse für den Lernerfolg der Schüler?", "Welche Form des Klassenmanagements der Lehrperson führt zu Lernerfolg der Schüler?", "Wie können Lehrkräfte Störenfriede in der Schulklasse zur Einsicht und zur Mitarbeit bringen?", "Wie handeln Schüler soziale Hierarchien in der Schulklasse aus?"], correctIndices: [0] },
  { id: "ps-207", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Welche Aspekte gehören zu den Tiefenstrukturen des Unterrichts?", options: ["Lehrervortrag, Klassengespräch, Gruppenarbeit, Partnerarbeit, Einzelarbeit", "Heterogenität, Differenzierung, Inklusion", "Lernzielorientierung, Leistungszielorientierung, Anspruchsniveau", "Klassenführung, kognitive Aktivierung, konstruktive Unterstützung"], correctIndices: [3] },
  { id: "ps-208", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Woran sind kognitiv aktivierende Aufgaben zu erkennen?", options: ["Nur die leistungsstarken Schülerinnen und Schüler finden die Lösung.", "Die Aufgaben gehen über den Lehrplan für die Jahrgangsstufe hinaus.", "Sie bieten mehr als EINEN Weg, um zur Lösung zu kommen.", "Sie zeigen den Schülerinnen und Schülern ihre Grenzen auf."], correctIndices: [2] },
  { id: "ps-209", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Die kompetente Klassenführung ist nach Kounin abhängig von...", options: ["der Autorität und Durchsetzungsfähigkeit der Lehrkraft.", "der fachlichen Kompetenz der Lehrperson.", "der Anzahl der Schülerinnen und Schüler mit Migrationshintergrund in der Klasse.", "der Fähigkeit der Lehrperson, den Unterricht ohne Unterbrechungen zu steuern."], correctIndices: [3] },
  { id: "ps-210", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Konstruktive Lernunterstützung gibt eine Lehrperson, indem sie...", options: ["freundlich aber bestimmt auf die Fehler hinweist, die Schülerinnen und Schüler machen.", "immer mal wieder zu erkennen gibt, dass sie auch nicht allwissend ist.", "einplant, dass Schülerinnen und Schüler unterschiedlich lange für eine Aufgabe brauchen.", "schwächeren Schülerinnen und Schülern zu verstehen gibt, dass eben nicht alle alles können."], correctIndices: [2] },
  { id: "ps-211", subject: "psychologie", topic: "Kooperatives Lernen & Unterricht", question: "Wenn ein Wissenschaftler die Lerneffekte von Gruppenpuzzle im Unterschied zu lehrergeleitetem Unterricht in verschiedenen Schulen und Klassen prüft, ist das methodisch gesehen", options: ["ein Laborexperiment", "eine Querschnittstudie", "eine Korrelationsstudie", "ein Feldexperiment"], correctIndices: [3] },
  { id: "ps-212", subject: "psychologie", topic: "Intelligenz & Testtheorie", question: "Welches Merkmal des wissenschaftlichen Tests erlaubt es, dass Testleistungen einzelner Personen in ein Leistungsspektrum eingeordnet werden können?", options: ["Validität", "Routine-Verfahren", "Ökonomie", "Normierung"], correctIndices: [3] },
  { id: "ps-213", subject: "psychologie", topic: "Experiment & Forschungsdesign", question: "Welche Aussage zum Feldexperiment ist zutreffend?", options: ["Das Feldexperiment basiert wie das Laborexperiment auf einer systematischen Bedingungsvariation.", "Beim Feldexperiment dürfen die Probanden nicht merken, dass sie an einer Untersuchung teilnehmen.", "Bei Feldexperimenten tritt die Variation der Bedingungen natürlich auf, weil es in der Alltagswelt stattfindet.", "Das Feldexperiment kann lediglich Korrelationshypothesen prüfen."], correctIndices: [0] },
];
